/**
 * PK Navigation - Programmatic navigation utilities for PK files
 *
 * Provides helpers for SPA navigation and route information.
 *
 * @example
 * ```typescript
 * // Navigate programmatically
 * await navigate('/products/123');
 *
 * // Navigate with options
 * await navigate('/dashboard', { replace: true, scroll: false });
 *
 * // Get current route info
 * const route = currentRoute();
 * console.log(route.path);   // '/products'
 * console.log(route.query);  // { category: 'electronics' }
 * ```
 */

// ============================================================================
// Types
// ============================================================================

export interface NavigateOptions {
    /** Replace current history entry instead of pushing (default: false) */
    replace?: boolean;
    /** Scroll to top after navigation (default: true) */
    scroll?: boolean;
    /** State object to pass to history.pushState/replaceState */
    state?: unknown;
    /** Skip the PPFramework navigation and do a full page load */
    fullReload?: boolean;
}

export interface RouteInfo {
    /** The pathname (e.g., '/products/123') */
    path: string;
    /** Query parameters as an object */
    query: Record<string, string>;
    /** Hash fragment without the # (e.g., 'section-1') */
    hash: string;
    /** Full URL */
    href: string;
    /** Origin (protocol + host) */
    origin: string;
    /** Get a specific query parameter */
    getParam(name: string): string | null;
    /** Check if a query parameter exists */
    hasParam(name: string): boolean;
    /** Get all values for a repeated query parameter */
    getParams(name: string): string[];
}

export interface NavigationGuard {
    /** Called before navigation. Return false to cancel. */
    beforeNavigate?: (to: string, from: string) => boolean | Promise<boolean>;
    /** Called after navigation completes */
    afterNavigate?: (to: string, from: string) => void;
}

// ============================================================================
// State
// ============================================================================

const navigationGuards: NavigationGuard[] = [];

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Parses query string into an object
 */
function parseQuery(search: string): Record<string, string> {
    const params = new URLSearchParams(search);
    const result: Record<string, string> = {};

    params.forEach((value, key) => {
        // If key already exists, keep first value (getParams for all values)
        if (!(key in result)) {
            result[key] = value;
        }
    });

    return result;
}

/**
 * Gets PPFramework instance if available
 */
function getFramework(): {navigate: (url: string, options?: NavigateOptions) => Promise<void>} | null {
    if (typeof window !== 'undefined' && 'PPFramework' in window) {
        const fw = (window as unknown as {PPFramework: unknown}).PPFramework;
        if (fw && typeof fw === 'object' && 'navigate' in fw) {
            return fw as {navigate: (url: string, options?: NavigateOptions) => Promise<void>};
        }
    }
    return null;
}

// ============================================================================
// Exported Functions
// ============================================================================

/**
 * Navigates to a new URL using PPFramework's SPA navigation
 *
 * Falls back to standard browser navigation if PPFramework is not available.
 *
 * @param url - URL to navigate to (can be relative or absolute)
 * @param options - Navigation options
 * @returns Promise that resolves when navigation completes
 *
 * @example
 * ```typescript
 * // Basic navigation
 * await navigate('/products');
 *
 * // Replace history entry (back button skips this page)
 * await navigate('/login', { replace: true });
 *
 * // Navigate without scrolling to top
 * await navigate('/products?page=2', { scroll: false });
 *
 * // Pass state to the new page
 * await navigate('/checkout', { state: { fromCart: true } });
 *
 * // Force full page reload
 * await navigate('/external-page', { fullReload: true });
 * ```
 */
export async function navigate(url: string, options: NavigateOptions = {}): Promise<void> {
    const {replace = false, scroll = true, state = null, fullReload = false} = options;

    const currentUrl = window.location.href;

    // Run beforeNavigate guards
    for (const guard of navigationGuards) {
        if (guard.beforeNavigate) {
            const allowed = await guard.beforeNavigate(url, currentUrl);
            if (!allowed) {
                return; // Navigation cancelled
            }
        }
    }

    // Full reload requested or external URL
    if (fullReload) {
        if (replace) {
            window.location.replace(url);
        } else {
            window.location.href = url;
        }
        return;
    }

    // Try PPFramework navigation first
    const framework = getFramework();
    if (framework) {
        await framework.navigate(url, {replace, scroll});
    } else {
        // Fall back to History API
        const method = replace ? 'replaceState' : 'pushState';
        window.history[method](state, '', url);

        if (scroll) {
            window.scrollTo(0, 0);
        }

        // Dispatch popstate event for any listeners
        window.dispatchEvent(new PopStateEvent('popstate', {state}));
    }

    // Run afterNavigate guards
    for (const guard of navigationGuards) {
        guard.afterNavigate?.(url, currentUrl);
    }
}

/**
 * Navigates back in history
 *
 * @example
 * ```typescript
 * goBack();
 * ```
 */
export function goBack(): void {
    window.history.back();
}

/**
 * Navigates forward in history
 *
 * @example
 * ```typescript
 * goForward();
 * ```
 */
export function goForward(): void {
    window.history.forward();
}

/**
 * Navigates to a specific point in history
 *
 * @param delta - Number of steps (negative for back, positive for forward)
 *
 * @example
 * ```typescript
 * go(-2); // Go back 2 pages
 * go(1);  // Go forward 1 page
 * ```
 */
export function go(delta: number): void {
    window.history.go(delta);
}

/**
 * Gets information about the current route
 *
 * @returns RouteInfo object with path, query, hash, and helper methods
 *
 * @example
 * ```typescript
 * const route = currentRoute();
 *
 * // Basic info
 * console.log(route.path);   // '/products/electronics'
 * console.log(route.query);  // { page: '2', sort: 'price' }
 * console.log(route.hash);   // 'reviews'
 * console.log(route.href);   // 'https://example.com/products/electronics?page=2#reviews'
 *
 * // Helper methods
 * const page = route.getParam('page');  // '2'
 * const hasSort = route.hasParam('sort');  // true
 * const tags = route.getParams('tag');  // ['a', 'b'] for ?tag=a&tag=b
 * ```
 */
export function currentRoute(): RouteInfo {
    const location = window.location;
    const searchParams = new URLSearchParams(location.search);

    return {
        path: location.pathname,
        query: parseQuery(location.search),
        hash: location.hash.replace(/^#/, ''),
        href: location.href,
        origin: location.origin,

        getParam(name: string): string | null {
            return searchParams.get(name);
        },

        hasParam(name: string): boolean {
            return searchParams.has(name);
        },

        getParams(name: string): string[] {
            return searchParams.getAll(name);
        }
    };
}

/**
 * Builds a URL with query parameters
 *
 * @param path - Base path
 * @param params - Query parameters to add
 * @param hash - Optional hash fragment
 * @returns Constructed URL string
 *
 * @example
 * ```typescript
 * const url = buildUrl('/products', { category: 'electronics', page: '2' });
 * // '/products?category=electronics&page=2'
 *
 * const urlWithHash = buildUrl('/docs', { version: '2.0' }, 'installation');
 * // '/docs?version=2.0#installation'
 * ```
 */
export function buildUrl(
    path: string,
    params?: Record<string, string | number | boolean | null | undefined>,
    hash?: string
): string {
    const url = new URL(path, window.location.origin);

    if (params) {
        for (const [key, value] of Object.entries(params)) {
            if (value !== null && value !== undefined) {
                url.searchParams.set(key, String(value));
            }
        }
    }

    if (hash) {
        url.hash = hash;
    }

    // Return relative URL (path + search + hash)
    return url.pathname + url.search + url.hash;
}

/**
 * Updates query parameters without full navigation
 *
 * Useful for filters, pagination, etc.
 *
 * @param params - Parameters to update (null to remove)
 * @param options - Navigation options
 *
 * @example
 * ```typescript
 * // Add/update parameters
 * updateQuery({ page: '2', sort: 'price' });
 *
 * // Remove a parameter
 * updateQuery({ filter: null });
 *
 * // Replace history entry
 * updateQuery({ tab: 'settings' }, { replace: true });
 * ```
 */
export async function updateQuery(
    params: Record<string, string | null | undefined>,
    options: NavigateOptions = {}
): Promise<void> {
    const url = new URL(window.location.href);

    for (const [key, value] of Object.entries(params)) {
        if (value === null || value === undefined) {
            url.searchParams.delete(key);
        } else {
            url.searchParams.set(key, value);
        }
    }

    await navigate(url.pathname + url.search + url.hash, {
        ...options,
        scroll: options.scroll ?? false // Don't scroll by default for query updates
    });
}

/**
 * Registers a navigation guard
 *
 * Guards can intercept navigation before it happens and optionally cancel it.
 *
 * @param guard - Guard object with beforeNavigate and/or afterNavigate callbacks
 * @returns Function to remove the guard
 *
 * @example
 * ```typescript
 * // Confirm before leaving a form
 * const removeGuard = registerNavigationGuard({
 *     beforeNavigate: (to, from) => {
 *         if (formHasChanges()) {
 *             return confirm('Leave without saving?');
 *         }
 *         return true;
 *     },
 *     afterNavigate: (to, from) => {
 *         console.log(`Navigated from ${from} to ${to}`);
 *     }
 * });
 *
 * // Remove guard when no longer needed
 * onCleanup(removeGuard);
 * ```
 */
export function registerNavigationGuard(guard: NavigationGuard): () => void {
    navigationGuards.push(guard);

    return () => {
        const index = navigationGuards.indexOf(guard);
        if (index > -1) {
            navigationGuards.splice(index, 1);
        }
    };
}

/**
 * Checks if the current path matches a pattern
 *
 * @param pattern - Path pattern (supports * wildcard and :param placeholders)
 * @returns True if current path matches
 *
 * @example
 * ```typescript
 * // Exact match
 * matchPath('/products'); // true if path is '/products'
 *
 * // Wildcard
 * matchPath('/products/*'); // true for '/products/123', '/products/abc', etc.
 *
 * // Parameter placeholder
 * matchPath('/products/:id'); // true for '/products/123'
 * ```
 */
export function matchPath(pattern: string): boolean {
    const currentPath = window.location.pathname;

    // Convert pattern to regex
    const regexPattern = pattern
        // Escape special regex characters except * and :
        .replace(/[.+?^${}()|[\]\\]/g, '\\$&')
        // Convert :param to capture group
        .replace(/:([^/]+)/g, '([^/]+)')
        // Convert * to match anything
        .replace(/\*/g, '.*');

    const regex = new RegExp(`^${regexPattern}$`);
    return regex.test(currentPath);
}

/**
 * Extracts path parameters from the current URL based on a pattern
 *
 * @param pattern - Path pattern with :param placeholders
 * @returns Object with extracted parameters, or null if pattern doesn't match
 *
 * @example
 * ```typescript
 * // Current path: '/products/electronics/laptop-123'
 * const params = extractParams('/products/:category/:id');
 * // { category: 'electronics', id: 'laptop-123' }
 *
 * // Pattern doesn't match
 * const params = extractParams('/users/:id');
 * // null
 * ```
 */
export function extractParams(pattern: string): Record<string, string> | null {
    const currentPath = window.location.pathname;

    // Extract parameter names
    const paramNames: string[] = [];
    const regexPattern = pattern
        .replace(/[.+?^${}()|[\]\\]/g, '\\$&')
        .replace(/:([^/]+)/g, (_, name: string) => {
            paramNames.push(name);
            return '([^/]+)';
        })
        .replace(/\*/g, '.*');

    const regex = new RegExp(`^${regexPattern}$`);
    const match = currentPath.match(regex);

    if (!match) {
        return null;
    }

    const params: Record<string, string> = {};
    paramNames.forEach((name, index) => {
        params[name] = match[index + 1];
    });

    return params;
}
