/**
 * PK Partial - Server-side partial reload functionality
 *
 * Supports graduated refresh levels:
 * - Level 0 (Default): Children only, root attrs preserved
 * - Level 1 (pp-refresh-root): Root refreshed with CSS scope preservation
 * - Level 2 (pp-own-attrs): Only declared attrs update, others preserved
 * - Level 3 (pp-no-refresh-attrs): All attrs update except listed (handled by morpher)
 */

import fragmentMorpher from '@/core/fragmentMorpher';

type RefreshLevel = 0 | 1 | 2 | 3;

/**
 * Detects the refresh level from element attributes.
 */
function detectRefreshLevel(el: HTMLElement): RefreshLevel {
    if (el.hasAttribute('pp-no-refresh-attrs')) {
        return 3;
    }
    if (el.hasAttribute('pp-own-attrs')) {
        return 2;
    }
    if (el.hasAttribute('pp-refresh-root')) {
        return 1;
    }
    return 0;
}

/**
 * Gets owned attributes from the pp-own-attrs attribute.
 */
function getOwnedAttributes(el: HTMLElement): string[] | undefined {
    const attr = el.getAttribute('pp-own-attrs');
    if (!attr) {
        return undefined;
    }
    return attr.split(',').map(s => s.trim()).filter(s => s.length > 0);
}

/**
 * Parses HTML string into an element for morphing.
 */
function parseHTML(html: string): HTMLElement | null {
    const parser = new DOMParser();
    const doc = parser.parseFromString(html, 'text/html');
    return doc.body.firstElementChild as HTMLElement | null;
}

/**
 * Options for partial reload with fine-grained control.
 */
export interface PartialReloadOptions {
    /** Query parameters to pass to the server */
    data?: Record<string, string | number | boolean>;
    /** Override the detected refresh level */
    level?: RefreshLevel;
    /** Override owned attributes for Level 2 (comma-separated) */
    ownedAttrs?: string[];
}

/**
 * Handle for interacting with a server-side partial.
 */
export interface PartialHandle {
    /** The container element for this partial */
    element: HTMLElement | null;

    /** Reload the partial from the server */
    reload(data?: Record<string, string | number | boolean>): Promise<void>;

    /** Reload with fine-grained options */
    reloadWithOptions(options: PartialReloadOptions): Promise<void>;
}

/**
 * Applies the appropriate morph based on refresh level.
 */
function applyRefresh(el: HTMLElement, newContent: HTMLElement, level: RefreshLevel, ownedAttrs?: string[]): void {
    switch (level) {
        case 0:
            // Level 0: Content-only (childrenOnly: true)
            // Root attrs preserved, only children update
            fragmentMorpher(el, newContent, {childrenOnly: true});
            break;

        case 1:
            // Level 1: Root refresh with scope preservation
            // Root attrs update, but parent CSS scopes in partial attr are preserved
            fragmentMorpher(el, newContent, {
                childrenOnly: false,
                preservePartialScopes: true
            });
            break;

        case 2:
            // Level 2: Owned attributes only
            // Only listed attrs update, all others (including parent contributions) preserved
            fragmentMorpher(el, newContent, {
                childrenOnly: false,
                preservePartialScopes: true,
                ownedAttributes: ownedAttrs
            });
            break;

        case 3:
            // Level 3: Already handled by pp-no-refresh-attrs in fragmentMorpher
            // All attrs update except those listed in pp-no-refresh-attrs
            fragmentMorpher(el, newContent, {
                childrenOnly: false,
                preservePartialScopes: true
            });
            break;
    }
}

/**
 * Performs the partial reload with the given options.
 */
async function performReload(el: HTMLElement, name: string, options: PartialReloadOptions): Promise<void> {
    const baseSrc = el.dataset.partialSrc ?? `/partials/${name}`;
    const url = options.data
        ? `${baseSrc}?${new URLSearchParams(options.data as Record<string, string>).toString()}`
        : baseSrc;

    el.classList.add('pp-loading');
    el.setAttribute('aria-busy', 'true');

    try {
        const response = await fetch(url);
        if (!response.ok) {
            throw new Error(`Failed to reload partial: ${response.status}`);
        }

        const html = await response.text();
        const newContent = parseHTML(html);

        if (!newContent) {
            console.warn(`[pk] partial "${name}" received empty or invalid response`);
            return;
        }

        // Detect level from element unless overridden
        const level = options.level ?? detectRefreshLevel(el);

        // Get owned attrs from element or options
        const ownedAttrs = options.ownedAttrs ?? getOwnedAttributes(el);

        applyRefresh(el, newContent, level, ownedAttrs);
    } catch (error) {
        console.error(`[pk] Failed to reload partial "${name}":`, {
            url,
            args: options.data,
            level,
            error
        });
        throw error;
    } finally {
        el.classList.remove('pp-loading');
        el.removeAttribute('aria-busy');
    }
}

/**
 * Gets a handle for a server-side partial by name.
 * The partial must have a data-partial attribute matching the name.
 *
 * @param name - The partial name (matches data-partial attribute)
 * @returns A handle for reloading the partial
 *
 * @example
 * ```html
 * <div data-partial="cart-summary" data-partial-src="/partials/cart">
 *   <!-- Server-rendered content -->
 * </div>
 * ```
 * ```ts
 * partial('cart-summary').reload({ highlight: 'new-item' });
 * ```
 *
 * @example
 * ```html
 * <!-- Level 1: Root refresh with scope preservation -->
 * <div data-partial="status" pp-refresh-root class="dynamic-class">
 *   ...
 * </div>
 * ```
 *
 * @example
 * ```html
 * <!-- Level 2: Only declared attributes update -->
 * <div data-partial="counter" pp-own-attrs="class,data-count">
 *   ...
 * </div>
 * ```
 */
export function partial(name: string): PartialHandle {
    const el = document.querySelector(`[data-partial="${name}"]`) as HTMLElement | null;

    return {
        element: el,

        async reload(data?: Record<string, string | number | boolean>): Promise<void> {
            if (!el) {
                console.warn(`[pk] partial "${name}" not found`);
                return;
            }
            return performReload(el, name, {data});
        },

        async reloadWithOptions(options: PartialReloadOptions): Promise<void> {
            if (!el) {
                console.warn(`[pk] partial "${name}" not found`);
                return;
            }
            return performReload(el, name, options);
        }
    };
}
