/**
 * HelperRegistry - Registry for helper functions that can be called from templates
 */

export type PPHelper = (element: HTMLElement, event: Event, ...args: string[]) => void;

export interface HelperRegistry {
    /** Register a helper function */
    register(name: string, helper: PPHelper): void;

    /** Get a helper function by name */
    get(name: string): PPHelper | undefined;

    /** Execute a helper function by name */
    execute(name: string, element: HTMLElement, event: Event, args: string[]): void;

    /** Check if a helper exists */
    has(name: string): boolean;
}

/**
 * Creates a HelperRegistry instance
 */
export function createHelperRegistry(): HelperRegistry {
    const registry = new Map<string, PPHelper>();

    return {
        register(name, helper) {
            if (registry.has(name)) {
                console.warn(`HelperRegistry: Overwriting already registered helper "${name}".`);
            }
            registry.set(name, helper);
        },

        get(name) {
            return registry.get(name);
        },

        execute(name, element, event, args) {
            const helper = registry.get(name);
            if (helper) {
                helper(element, event, ...args);
            } else {
                console.warn(`HelperRegistry: Unknown helper "${name}"`);
            }
        },

        has(name) {
            return registry.has(name);
        }
    };
}
