/**
 * PK Action - Action Descriptor Pattern for Optimistic UI
 *
 * Provides a fluent API for defining server actions with optimistic updates,
 * error handling, and loading states.
 *
 * @example
 * ```typescript
 * // Simple action
 * export function likePost(postId: number) {
 *     return action('likePost', postId)
 *         .optimistic(() => {
 *             refs.likeIcon.textContent = '❤️';
 *             refs.likeCount.textContent = String(Number(refs.likeCount.textContent) + 1);
 *         })
 *         .onError(() => {
 *             refs.likeIcon.textContent = '🤍';
 *             refs.likeCount.textContent = String(Number(refs.likeCount.textContent) - 1);
 *         })
 *         .loading(true);
 * }
 *
 * // With type-safe response
 * export function createOrder(data: OrderData) {
 *     return action<Order>('createOrder', data)
 *         .onSuccess((order) => navigate(`/orders/${order.id}`))
 *         .onError((err) => showFieldErrors(err.validationErrors));
 * }
 * ```
 */

// ============================================================================
// Types
// ============================================================================

/**
 * HTTP methods supported by action descriptors
 */
export type ActionMethod = 'GET' | 'POST' | 'PUT' | 'PATCH' | 'DELETE';

/**
 * Retry backoff strategy
 */
export type RetryBackoff = 'linear' | 'exponential';

/**
 * Retry configuration
 */
export interface RetryConfig {
    /** Number of retry attempts */
    attempts: number;
    /** Backoff strategy (default: exponential) */
    backoff?: RetryBackoff;
}

/**
 * Error returned when an action fails
 */
export interface ActionError {
    /** HTTP status code (0 for network errors) */
    status: number;
    /** Error message */
    message: string;
    /** Field-level validation errors */
    validationErrors?: Record<string, string[]>;
    /** Raw response data */
    data?: unknown;
}

/**
 * Creates an ActionError instance with computed properties
 */
export function createActionError(
    status: number,
    message: string,
    validationErrors?: Record<string, string[]>,
    data?: unknown
): ActionError & { isNetworkError: boolean; isValidationError: boolean; isAuthError: boolean } {
    return {
        status,
        message,
        validationErrors,
        data,
        get isNetworkError(): boolean {
            return this.status === 0;
        },
        get isValidationError(): boolean {
            return this.status === 422 && this.validationErrors !== undefined;
        },
        get isAuthError(): boolean {
            return this.status === 401 || this.status === 403;
        }
    };
}

/**
 * Describes a server action with lifecycle callbacks
 */
export interface ActionDescriptor<T = unknown> {
    /** Server action name to call */
    action: string;

    /** Arguments to pass to the action */
    args?: unknown[];

    /** HTTP method (default: POST) */
    method?: ActionMethod;

    /** Run immediately before server call */
    optimistic?: () => void;

    /** Run after successful response; can return another action to chain */
    onSuccess?: (response: T) => void | ActionDescriptor;

    /** Run if server returns error */
    onError?: (error: ActionError) => void;

    /** Run always (success or error) */
    onComplete?: () => void;

    /** Loading state target: true = element, string = selector, HTMLElement = specific element */
    loading?: string | HTMLElement | boolean;

    /** Debounce ms before sending (not implemented in Phase 1) */
    debounce?: number;

    /** Retry configuration (not implemented in Phase 1) */
    retry?: RetryConfig;
}

// ============================================================================
// Detection
// ============================================================================

/**
 * Checks if a value is an ActionDescriptor
 *
 * Uses duck typing: checks for 'action' property of type string.
 */
export function isActionDescriptor(value: unknown): value is ActionDescriptor {
    return value !== null &&
        typeof value === 'object' &&
        typeof (value as ActionDescriptor).action === 'string';
}

// ============================================================================
// Builder
// ============================================================================

/**
 * Fluent builder for ActionDescriptor
 *
 * Implements ActionDescriptor interface so it can be used directly without calling build().
 */
export class ActionBuilder<T = unknown> implements ActionDescriptor<T> {
    private readonly _action: string;
    private readonly _args: unknown[];
    private _method?: ActionMethod;
    private _optimistic?: () => void;
    private _onSuccess?: (response: T) => void | ActionDescriptor;
    private _onError?: (error: ActionError) => void;
    private _onComplete?: () => void;
    private _loading?: string | HTMLElement | boolean;
    private _debounce?: number;
    private _retry?: RetryConfig;

    constructor(actionName: string, args: unknown[]) {
        this._action = actionName;
        this._args = args;
    }

    // ========================================================================
    // ActionDescriptor interface getters
    // ========================================================================

    get action(): string {
        return this._action;
    }

    get args(): unknown[] {
        return this._args;
    }

    get method(): ActionMethod | undefined {
        return this._method;
    }

    get optimistic(): (() => void) | undefined {
        return this._optimistic;
    }

    get onSuccess(): ((response: T) => void | ActionDescriptor) | undefined {
        return this._onSuccess;
    }

    get onError(): ((error: ActionError) => void) | undefined {
        return this._onError;
    }

    get onComplete(): (() => void) | undefined {
        return this._onComplete;
    }

    get loading(): string | HTMLElement | boolean | undefined {
        return this._loading;
    }

    get debounce(): number | undefined {
        return this._debounce;
    }

    get retry(): RetryConfig | undefined {
        return this._retry;
    }

    // ========================================================================
    // Fluent setters
    // ========================================================================

    /**
     * Set HTTP method
     */
    setMethod(method: ActionMethod): this {
        this._method = method;
        return this;
    }

    /**
     * Set optimistic update callback
     *
     * Runs immediately before the server request.
     */
    setOptimistic(fn: () => void): this {
        this._optimistic = fn;
        return this;
    }

    /**
     * Set success callback
     *
     * Can return another ActionDescriptor to chain actions.
     */
    setOnSuccess(fn: (response: T) => void | ActionDescriptor): this {
        this._onSuccess = fn;
        return this;
    }

    /**
     * Set error callback
     *
     * Use this to rollback optimistic updates.
     */
    setOnError(fn: (error: ActionError) => void): this {
        this._onError = fn;
        return this;
    }

    /**
     * Set complete callback
     *
     * Runs after success or error, always.
     */
    setOnComplete(fn: () => void): this {
        this._onComplete = fn;
        return this;
    }

    /**
     * Set loading state target
     *
     * - `true`: Apply to trigger element
     * - `string`: CSS selector
     * - `HTMLElement`: Specific element
     */
    setLoading(target: string | HTMLElement | boolean): this {
        this._loading = target;
        return this;
    }

    /**
     * Set debounce delay (Phase 2)
     */
    setDebounce(ms: number): this {
        this._debounce = ms;
        return this;
    }

    /**
     * Set retry configuration
     */
    setRetry(attempts: number, backoff?: RetryBackoff): this {
        this._retry = {attempts, backoff};
        return this;
    }

    // ========================================================================
    // Short aliases (matching doc2.md API examples)
    // ========================================================================

    /**
     * Alias for setMethod()
     * @see setMethod
     */
    withMethod(method: ActionMethod): this {
        return this.setMethod(method);
    }

    /**
     * Alias for setOptimistic() - matches doc2.md API
     * @see setOptimistic
     *
     * @example
     * ```typescript
     * action('likePost', postId)
     *     .optimistic(() => refs.icon.textContent = '❤️')
     * ```
     */
    withOptimistic(fn: () => void): this {
        return this.setOptimistic(fn);
    }

    /**
     * Alias for setOnSuccess() - matches doc2.md API
     * @see setOnSuccess
     */
    withOnSuccess(fn: (response: T) => void | ActionDescriptor): this {
        return this.setOnSuccess(fn);
    }

    /**
     * Alias for setOnError() - matches doc2.md API
     * @see setOnError
     */
    withOnError(fn: (error: ActionError) => void): this {
        return this.setOnError(fn);
    }

    /**
     * Alias for setOnComplete()
     * @see setOnComplete
     */
    withOnComplete(fn: () => void): this {
        return this.setOnComplete(fn);
    }

    /**
     * Alias for setLoading() - matches doc2.md API
     * @see setLoading
     *
     * @example
     * ```typescript
     * action('saveForm')
     *     .loading(true)
     *     .loading('#submit-btn')
     * ```
     */
    withLoading(target: string | HTMLElement | boolean): this {
        return this.setLoading(target);
    }

    /**
     * Alias for setDebounce() - matches doc2.md API
     * @see setDebounce
     */
    withDebounce(ms: number): this {
        return this.setDebounce(ms);
    }

    /**
     * Alias for setRetry() - matches doc2.md API
     * @see setRetry
     *
     * @example
     * ```typescript
     * action('saveDocument')
     *     .retry(3, 'exponential')
     * ```
     */
    withRetry(attempts: number, backoff?: RetryBackoff): this {
        return this.setRetry(attempts, backoff);
    }

    /**
     * Build the final ActionDescriptor
     *
     * Note: The builder itself implements ActionDescriptor, so calling build()
     * is optional. You can use the builder directly.
     */
    build(): ActionDescriptor<T> {
        return {
            action: this._action,
            args: this._args,
            method: this._method,
            optimistic: this._optimistic,
            onSuccess: this._onSuccess,
            onError: this._onError,
            onComplete: this._onComplete,
            loading: this._loading,
            debounce: this._debounce,
            retry: this._retry
        };
    }
}

// ============================================================================
// Helper Function
// ============================================================================

/**
 * Creates an action builder for the given action name and arguments
 *
 * @param name - Server action name
 * @param args - Arguments to pass to the action
 * @returns ActionBuilder with fluent API
 *
 * @example
 * ```typescript
 * // Simple usage
 * return action('likePost', postId);
 *
 * // With optimistic update
 * return action('likePost', postId)
 *     .setOptimistic(() => refs.icon.textContent = '❤️')
 *     .setOnError(() => refs.icon.textContent = '🤍');
 *
 * // With type-safe response
 * return action<Order>('createOrder', orderData)
 *     .setOnSuccess((order) => console.log(order.id));
 * ```
 */
export function action<T = unknown>(name: string, ...args: unknown[]): ActionBuilder<T> {
    return new ActionBuilder<T>(name, args);
}
