/**
 * A11yAnnouncer - Accessibility announcements for screen readers
 *
 * Creates a hidden aria-live region to announce dynamic content changes
 * to assistive technology users, including:
 * - Route changes
 * - Loading states
 * - Error messages
 */

const ANNOUNCER_ID = 'ppf-a11y-announcer';

/**
 * Announcement priority levels
 */
export type AnnouncementPriority = 'polite' | 'assertive';

/**
 * Accessibility announcer interface
 */
export interface A11yAnnouncer {
    /**
     * Announce a message to screen readers
     * @param message - The message to announce
     * @param priority - 'polite' (default) waits for silence, 'assertive' interrupts
     */
    announce(message: string, priority?: AnnouncementPriority): void;

    /**
     * Announce a navigation event
     * @param pageTitle - The title of the new page
     */
    announceNavigation(pageTitle: string): void;

    /**
     * Announce loading state
     */
    announceLoading(): void;

    /**
     * Announce an error
     * @param errorMessage - The error message to announce
     */
    announceError(errorMessage: string): void;

    /** Clean up the announcer element */
    destroy(): void;
}

/**
 * Creates the visually hidden announcer element
 */
function createAnnouncerElement(): HTMLElement {
    const element = document.createElement('div');
    element.id = ANNOUNCER_ID;
    element.setAttribute('role', 'status');
    element.setAttribute('aria-live', 'polite');
    element.setAttribute('aria-atomic', 'true');

    // Visually hidden but accessible to screen readers
    element.style.cssText = [
        'position:absolute',
        'width:1px',
        'height:1px',
        'padding:0',
        'margin:-1px',
        'overflow:hidden',
        'clip:rect(0,0,0,0)',
        'white-space:nowrap',
        'border:0',
    ].join(';');

    return element;
}

/**
 * Creates an A11yAnnouncer instance
 */
export function createA11yAnnouncer(): A11yAnnouncer {
    // Check for existing announcer (e.g., from previous init)
    let element = document.getElementById(ANNOUNCER_ID);
    if (!element) {
        element = createAnnouncerElement();
        document.body.appendChild(element);
    }

    const announce = (message: string, priority: AnnouncementPriority = 'polite'): void => {
        if (!element) {
            return;
        }

        // Update aria-live attribute for priority
        element.setAttribute('aria-live', priority);

        // Clear and re-set content to force announcement
        // Using requestAnimationFrame ensures the DOM has time to register the change
        element.textContent = '';
        requestAnimationFrame(() => {
            if (element) {
                element.textContent = message;
            }
        });
    };

    return {
        announce,

        announceNavigation(pageTitle: string): void {
            announce(`Navigated to ${pageTitle}`);
        },

        announceLoading(): void {
            announce('Loading page');
        },

        announceError(errorMessage: string): void {
            announce(errorMessage, 'assertive');
        },

        destroy(): void {
            element?.remove();
            element = null;
        }
    };
}
