/**
 * PK SSE - Server-Sent Events support for real-time updates
 *
 * Alternative to polling via autoRefresh. SSE provides real-time server push
 * with automatic reconnection and efficient resource usage.
 *
 * @example
 * ```typescript
 * // Simple subscription - reloads partial when server sends update
 * const unsubscribe = subscribeToUpdates('live-orders', {
 *     url: '/api/events/orders'
 * });
 *
 * // With custom message handler
 * const unsubscribe = subscribeToUpdates('notifications', {
 *     url: '/api/events/notifications',
 *     onMessage: (data) => {
 *         console.log('Received:', data);
 *         // Custom handling instead of auto-reload
 *     }
 * });
 *
 * // Stop listening
 * unsubscribe();
 * ```
 */

import {reloadPartial} from './coordination';

// ============================================================================
// Constants
// ============================================================================

/** Maximum backoff multiplier for reconnection delay */
const MAX_RECONNECT_BACKOFF_MULTIPLIER = 5;

// ============================================================================
// Types
// ============================================================================

export interface SSEOptions {
    /** SSE endpoint URL */
    url: string;
    /** Custom message handler (overrides default partial reload) */
    onMessage?: (data: unknown) => void;
    /** Error handling: 'reconnect' (default) or 'stop' */
    onError?: 'reconnect' | 'stop';
    /** Reconnection delay in ms (default: 3000) */
    reconnectDelay?: number;
    /** Maximum reconnection attempts (default: 10) */
    maxReconnects?: number;
    /** Event types to listen for (default: ['message']) */
    eventTypes?: string[];
    /** Called when connection opens */
    onOpen?: () => void;
    /** Called when connection closes */
    onClose?: () => void;
}

export interface SSESubscription {
    /** Stop listening and close connection */
    unsubscribe: () => void;
    /** Current connection state */
    readonly state: 'connecting' | 'open' | 'closed' | 'error';
    /** Number of reconnection attempts */
    readonly reconnectCount: number;
}

// ============================================================================
// Implementation
// ============================================================================

/**
 * Subscribes to Server-Sent Events for a partial
 *
 * When the server sends an event, the partial is automatically reloaded.
 * Alternatively, provide a custom onMessage handler to process events yourself.
 *
 * @param name - Partial name to reload on message
 * @param options - SSE configuration
 * @returns Cleanup function to stop listening
 *
 * @example
 * ```typescript
 * // Auto-reload partial when server sends update
 * const stop = subscribeToUpdates('live-metrics', {
 *     url: '/api/events/metrics'
 * });
 *
 * // Stop on navigation or cleanup
 * onCleanup(stop);
 * ```
 */
export function subscribeToUpdates(name: string, options: SSEOptions): () => void {
    const {
        url,
        onMessage,
        onError = 'reconnect',
        reconnectDelay = 3000,
        maxReconnects = 10,
        eventTypes = ['message'],
        onOpen,
        onClose
    } = options;

    let eventSource: EventSource | null = null;
    let reconnectCount = 0;
    let reconnectTimeout: ReturnType<typeof setTimeout> | null = null;
    let stopped = false;

    /**
     * Handle incoming message
     */
    const handleMessage = (event: MessageEvent): void => {
        if (stopped) {
            return;
        }

        let data: unknown = event.data;

        // Try to parse JSON
        if (typeof event.data === 'string') {
            try {
                data = JSON.parse(event.data) as unknown;
            } catch {
                // Keep as string if not valid JSON
            }
        }

        if (onMessage) {
            // Custom handler
            onMessage(data);
        } else {
            // Default: reload the partial
            void reloadPartial(name);
        }
    };

    /**
     * Handle connection open
     */
    const handleOpen = (): void => {
        reconnectCount = 0;
        onOpen?.();
    };

    /**
     * Handle connection error
     */
    const handleError = (): void => {
        if (stopped) {
            return;
        }

        // Close existing connection
        eventSource?.close();
        eventSource = null;

        if (onError === 'stop') {
            stopped = true;
            console.warn(`[pk] SSE connection to "${url}" failed, stopping`);
            onClose?.();
            return;
        }

        // Reconnect
        if (reconnectCount < maxReconnects) {
            reconnectCount++;
            const delay = reconnectDelay * Math.min(reconnectCount, MAX_RECONNECT_BACKOFF_MULTIPLIER);

            console.warn(`[pk] SSE connection to "${url}" lost, reconnecting in ${delay}ms (attempt ${reconnectCount}/${maxReconnects})`);

            reconnectTimeout = setTimeout(() => {
                if (!stopped) {
                    connect();
                }
            }, delay);
        } else {
            stopped = true;
            console.error(`[pk] SSE connection to "${url}" failed after ${maxReconnects} attempts`);
            onClose?.();
        }
    };

    /**
     * Establish SSE connection
     */
    const connect = (): void => {
        if (stopped) {
            return;
        }

        try {
            eventSource = new EventSource(url);

            eventSource.onopen = handleOpen;
            eventSource.onerror = handleError;

            // Add listeners for specified event types
            for (const eventType of eventTypes) {
                eventSource.addEventListener(eventType, handleMessage);
            }
        } catch (error) {
            console.error(`[pk] Failed to create SSE connection to "${url}":`, {
                error,
                reconnectCount,
                maxReconnects
            });
            handleError();
        }
    };

    // Start connection
    connect();

    // Return cleanup function
    return () => {
        stopped = true;

        if (reconnectTimeout) {
            clearTimeout(reconnectTimeout);
            reconnectTimeout = null;
        }

        if (eventSource) {
            eventSource.close();
            eventSource = null;
        }

        onClose?.();
    };
}

/**
 * Creates an SSE subscription with more detailed state tracking
 *
 * Use this when you need to monitor connection state or access reconnect count.
 *
 * @example
 * ```typescript
 * const subscription = createSSESubscription('live-data', {
 *     url: '/api/events/data',
 *     onOpen: () => console.log('Connected'),
 *     onClose: () => console.log('Disconnected')
 * });
 *
 * // Check state
 * console.log(subscription.state); // 'connecting', 'open', 'closed', or 'error'
 * console.log(subscription.reconnectCount);
 *
 * // Stop
 * subscription.unsubscribe();
 * ```
 */
export function createSSESubscription(name: string, options: SSEOptions): SSESubscription {
    let state: 'connecting' | 'open' | 'closed' | 'error' = 'connecting';
    let reconnectCount = 0;

    const unsubscribe = subscribeToUpdates(name, {
        ...options,
        onOpen: () => {
            state = 'open';
            reconnectCount = 0;
            options.onOpen?.();
        },
        onClose: () => {
            state = 'closed';
            options.onClose?.();
        },
        onError: options.onError
    });

    return {
        unsubscribe,
        get state() {
            return state;
        },
        get reconnectCount() {
            return reconnectCount;
        }
    };
}
