/**
 * PK Event Bus - Cross-component event communication
 */

type EventHandler = (data: unknown) => void;
const listeners = new Map<string, Set<EventHandler>>();

/**
 * Simple event bus for cross-component communication.
 *
 * @example
 * ```ts
 * // In PK page
 * bus.on('cart:updated', (items) => {
 *   partial('cart-summary').reload();
 * });
 *
 * // In PKC component
 * bus.emit('cart:updated', { itemCount: 5 });
 * ```
 */
export const bus = {
    /**
     * Emit an event to all listeners.
     * @param event - Event name
     * @param data - Optional data to pass to listeners
     */
    emit(event: string, data?: unknown): void {
        const handlers = listeners.get(event);
        if (handlers) {
            handlers.forEach(fn => {
                try {
                    fn(data);
                } catch (error) {
                    console.error(`[pk] Error in bus handler for "${event}":`, error);
                }
            });
        }
    },

    /**
     * Subscribe to an event.
     * @param event - Event name
     * @param handler - Handler function
     * @returns Unsubscribe function
     */
    on(event: string, handler: EventHandler): () => void {
        let eventListeners = listeners.get(event);
        if (!eventListeners) {
            eventListeners = new Set();
            listeners.set(event, eventListeners);
        }
        eventListeners.add(handler);

        // Return unsubscribe function
        return () => {
            listeners.get(event)?.delete(handler);
        };
    },

    /**
     * Subscribe to an event once (auto-unsubscribes after first call).
     * @param event - Event name
     * @param handler - Handler function
     * @returns Unsubscribe function (in case you want to cancel before it fires)
     */
    once(event: string, handler: EventHandler): () => void {
        const wrappedHandler = (data: unknown) => {
            listeners.get(event)?.delete(wrappedHandler);
            handler(data);
        };
        return this.on(event, wrappedHandler);
    },

    /**
     * Remove all listeners for an event, or all listeners if no event specified.
     * @param event - Optional event name
     */
    off(event?: string): void {
        if (event) {
            listeners.delete(event);
        } else {
            listeners.clear();
        }
    }
};
