/**
 * PpSvgInline - Custom element that fetches and inlines SVG content.
 *
 * This element allows CSS styling of SVG internals (fill, stroke, etc.)
 * which is not possible when using <img> tags for SVGs.
 *
 * Usage in PKC templates:
 *   <piko:svg src="icons/arrow.svg" class="icon" />
 *
 * Compiles to:
 *   <piko:svg-inline src="/_pp/assets/icons/arrow.svg" class="icon"></piko:svg-inline>
 *
 * At runtime, this element fetches the SVG and replaces itself with the inline
 * SVG content. The replacement is registered with the VDOM renderer so it can
 * adopt the SVG element instead of recreating on every update.
 */

import {replaceElementWithTracking} from '@/vdom/renderer';

// SVG cache to avoid refetching the same SVG multiple times
const svgCache = new Map<string, string>();

// In-flight fetch promises to prevent duplicate requests
const fetchPromises = new Map<string, Promise<string>>();

export class PpSvgInline extends HTMLElement {
    private _src = '';
    private _abortController: AbortController | null = null;

    static get observedAttributes(): string[] {
        return ['src'];
    }

    get src(): string {
        return this._src;
    }

    set src(value: string) {
        if (this._src !== value) {
            this._src = value;
            this.setAttribute('src', value);
            void this._loadSvg();
        }
    }

    connectedCallback(): void {
        const srcAttr = this.getAttribute('src');
        if (srcAttr && srcAttr !== this._src) {
            this._src = srcAttr;
            void this._loadSvg();
        }
    }

    disconnectedCallback(): void {
        this._abortController?.abort();
        this._abortController = null;
    }

    attributeChangedCallback(name: string, oldValue: string | null, newValue: string | null): void {
        if (name === 'src' && newValue !== oldValue && newValue !== this._src) {
            this._src = newValue ?? '';
            void this._loadSvg();
        }
    }

    private async _loadSvg(): Promise<void> {
        const src = this._src;
        if (!src) {
            return;
        }

        // Abort any in-flight request
        this._abortController?.abort();
        this._abortController = new AbortController();
        const signal = this._abortController.signal;

        try {
            const svgContent = await this._fetchSvg(src, signal);
            if (signal.aborted) {
                return;
            }

            this._inlineSvg(svgContent);
        } catch (err) {
            if (signal.aborted) {
                return;
            }
            console.warn(`PpSvgInline: Failed to load SVG from ${src}`, err);
            // Show error placeholder
            this.innerHTML = `<!-- piko:svg-inline error: failed to load ${src} -->`;
        }
    }

    private async _fetchSvg(src: string, signal: AbortSignal): Promise<string> {
        // Check cache first
        const cached = svgCache.get(src);
        if (cached) {
            return cached;
        }

        // Check if fetch is already in progress
        const existingPromise = fetchPromises.get(src);
        if (existingPromise) {
            return existingPromise;
        }

        // Start new fetch
        const fetchPromise = this._doFetch(src, signal);
        fetchPromises.set(src, fetchPromise);

        try {
            const result = await fetchPromise;
            svgCache.set(src, result);
            return result;
        } finally {
            fetchPromises.delete(src);
        }
    }

    private async _doFetch(src: string, signal: AbortSignal): Promise<string> {
        const response = await fetch(src, {signal});
        if (!response.ok) {
            throw new Error(`HTTP ${response.status}: ${response.statusText}`);
        }
        const text = await response.text();

        // Validate it's actually SVG
        if (!text.includes('<svg')) {
            throw new Error('Response is not valid SVG');
        }

        return text;
    }

    private _inlineSvg(svgContent: string): void {
        // Parse the SVG
        const parser = new DOMParser();
        const doc = parser.parseFromString(svgContent, 'image/svg+xml');
        const svgElement = doc.querySelector('svg');

        if (!svgElement) {
            console.warn('PpSvgInline: No SVG element found in response');
            return;
        }

        // Copy attributes from this element to the SVG (class, style, etc.)
        // but preserve SVG-specific attributes like viewBox
        for (const attr of Array.from(this.attributes)) {
            if (attr.name === 'src') {
                continue; // Don't copy src
            }
            if (attr.name === 'class') {
                // Merge classes
                const existingClass = svgElement.getAttribute('class') ?? '';
                const mergedClass = existingClass
                    ? `${existingClass} ${attr.value}`
                    : attr.value;
                svgElement.setAttribute('class', mergedClass);
            } else if (!svgElement.hasAttribute(attr.name)) {
                // Only set if SVG doesn't already have this attribute
                svgElement.setAttribute(attr.name, attr.value);
            }
        }

        // Replace this element with the SVG, registering with VDOM so it
        // can adopt the replacement instead of recreating on every update.
        // Watch 'src' so that if it changes, we refetch the new SVG.
        replaceElementWithTracking(this, svgElement, { watchProps: ['src'] });
    }
}

/**
 * Register the piko:svg-inline custom element.
 * Safe to call multiple times - will only register once.
 */
export function registerPpSvgInline(): void {
    if (!customElements.get('piko:svg-inline')) {
        customElements.define('piko:svg-inline', PpSvgInline);
    }
}
