/**
 * PK Utilities - debounce, throttle
 */

/**
 * Creates a debounced version of a function that delays execution
 * until after the specified milliseconds have elapsed since the last call.
 *
 * @param fn - Function to debounce
 * @param ms - Delay in milliseconds
 * @returns Debounced function
 *
 * @example
 * ```ts
 * refs.search.addEventListener('input', debounce(() => {
 *   partial('results').reload({ q: refs.search.value });
 * }, 300));
 * ```
 */
export function debounce<T extends (...args: unknown[]) => unknown>(
    fn: T,
    ms: number
): (...args: Parameters<T>) => void {
    let timeoutId: ReturnType<typeof setTimeout>;

    return (...args: Parameters<T>) => {
        clearTimeout(timeoutId);
        timeoutId = setTimeout(() => fn(...args), ms);
    };
}

/**
 * Creates a throttled version of a function that only executes
 * at most once per specified milliseconds.
 *
 * @param fn - Function to throttle
 * @param ms - Minimum interval in milliseconds
 * @returns Throttled function
 *
 * @example
 * ```ts
 * window.addEventListener('scroll', throttle(() => {
 *   // Handle scroll
 * }, 100));
 * ```
 */
export function throttle<T extends (...args: unknown[]) => unknown>(
    fn: T,
    ms: number
): (...args: Parameters<T>) => void {
    let lastCall = 0;

    return (...args: Parameters<T>) => {
        const now = Date.now();
        if (now - lastCall >= ms) {
            lastCall = now;
            fn(...args);
        }
    };
}
