/**
 * DOMBinder - Parses and binds event handlers to DOM elements
 *
 * Handles piko:a, p-on:*, p-event:*, and p-modal:* attributes
 */

import type {HelperRegistry} from './HelperRegistry';
import {findClosestMatch, getGlobalPageContext} from './PageContext';
import {isActionDescriptor} from '@/pk/action';
import {handleAction} from '@/core/ActionExecutor';

export interface ActionArg {
    t: 's' | 'v' | 'e'; // type: 's' for static, 'v' for variable, 'e' for $event placeholder
    v?: string | number | boolean; // Optional for 'e' type (event injected at runtime)
}

interface ActionPayload {
    f: string;
    a: ActionArg[];
}

/**
 * Resolves action arguments, injecting the event object where 'e' type appears.
 * This implements position-aware event injection based on $event placeholders.
 *
 * @param args - The action arguments from the payload
 * @param event - The browser event to inject
 * @returns Array of resolved values with event injected at correct positions
 */
function resolveArgsWithEvent(args: ActionArg[], event: Event): unknown[] {
    return args.map(a => (a.t === 'e' ? event : a.v));
}

export interface OpenModalOptions {
    selector: string;
    params: Map<string, string>;
    title: string;
    message: string;
    cancelLabel: string;
    confirmLabel: string;
    confirmAction: string;
    element: HTMLElement;
}

export interface DOMBinderCallbacks {
    /** Called when a piko:a is clicked */
    onNavigate: (url: string, event: MouseEvent) => void;

    /** Called when a server action should be executed */
    onServerAction: (
        name: string,
        element: HTMLElement,
        event: Event,
        method: string,
        args: ActionArg[]
    ) => void;

    /** Called when a modal should be opened */
    onOpenModal: (options: OpenModalOptions) => void;
}

export interface DOMBinder {
    /** Bind all handlers within a root element */
    bind(root: HTMLElement): void;

    /** Bind only piko:a handlers */
    bindLinks(root: HTMLElement): void;

    /** Bind only action handlers (p-on, p-event) */
    bindActions(root: HTMLElement): void;
}

type EventHandlerFunc = (event: Event) => void;
type HandlerResult = { eventName: string; handlerFunc: EventHandlerFunc | null };

const BOUND_MARKER = 'pp-ev-bound';

function getAttrTrimmed(el: HTMLElement, attr: string): string {
    return el.getAttribute(attr)?.trim() ?? '';
}

const P_MODAL_PARAM_PREFIX = 'p-modal-param:';
const P_ON_PREFIX_LEN = 5; // 'p-on:'.length
const P_EVENT_PREFIX_LEN = 8; // 'p-event:'.length

/**
 * URI schemes that should be handled natively by the browser/OS.
 * These trigger platform-specific actions (phone calls, emails, etc.)
 * and should not be intercepted by SPA navigation.
 */
const NATIVE_URI_SCHEMES: readonly string[] = [
    'tel:',
    'mailto:',
    'sms:',
    'geo:',
    'webcal:',
    'facetime:',
    'facetime-audio:',
    'skype:',
    'whatsapp:',
    'viber:',
    'maps:',
    'comgooglemaps:'
];

/**
 * URI schemes that should be blocked entirely for security reasons.
 * These could be used for XSS or other attacks.
 */
// eslint-disable-next-line no-script-url -- These are blocked schemes, not executed
const BLOCKED_URI_SCHEMES: readonly string[] = ['javascript:', 'data:', 'blob:', 'file:'];

function isNativeScheme(href: string): boolean {
    const lowerHref = href.toLowerCase();
    return NATIVE_URI_SCHEMES.some(scheme => lowerHref.startsWith(scheme));
}

function isBlockedScheme(href: string): boolean {
    const lowerHref = href.toLowerCase();
    return BLOCKED_URI_SCHEMES.some(scheme => lowerHref.startsWith(scheme));
}

/**
 * Walk up the DOM to find the closest partial's hashed ID.
 * Returns undefined if element is not within a partial.
 */
function findPartialScope(el: HTMLElement): string | undefined {
    let current: HTMLElement | null = el;
    while (current) {
        const partialId = current.getAttribute('partial');
        if (partialId) {
            return partialId;
        }
        current = current.parentElement;
    }
    return undefined;
}

/**
 * Parse function reference for explicit scope syntax: "@partial-name.functionName" or "functionName"
 * The @ prefix indicates a cross-partial call that should broadcast to all instances.
 */
function parseFunctionReference(ref: string): { partialName: string | null; fnName: string } {
    if (ref.startsWith('@')) {
        const dotIndex = ref.indexOf('.');
        if (dotIndex > 1) {
            return {
                partialName: ref.slice(1, dotIndex), // Remove @ prefix
                fnName: ref.slice(dotIndex + 1)
            };
        }
    }
    return {partialName: null, fnName: ref};
}

function collectModalParams(el: HTMLElement): Map<string, string> {
    const params = new Map<string, string>();
    for (const {name, value} of Array.from(el.attributes)) {
        if (name.startsWith(P_MODAL_PARAM_PREFIX)) {
            const paramName = name.slice(P_MODAL_PARAM_PREFIX.length).trim();
            params.set(paramName, value.trim());
        }
    }
    return params;
}

function createModalHandler(el: HTMLElement, callbacks: DOMBinderCallbacks): EventHandlerFunc {
    return () => {
        callbacks.onOpenModal({
            selector: getAttrTrimmed(el, 'p-modal:selector'),
            params: collectModalParams(el),
            title: getAttrTrimmed(el, 'p-modal:title'),
            message: getAttrTrimmed(el, 'p-modal:message'),
            cancelLabel: getAttrTrimmed(el, 'p-modal:cancel_label'),
            confirmLabel: getAttrTrimmed(el, 'p-modal:confirm_label'),
            confirmAction: getAttrTrimmed(el, 'p-modal:confirm_action'),
            element: el
        });
    };
}

function createActionHandler(
    key: string,
    encodedPayload: string,
    isCustomEvent: boolean,
    el: HTMLElement,
    helperRegistry: HelperRegistry,
    callbacks: DOMBinderCallbacks
): HandlerResult {
    const parts = key.split('.');
    const eventName = parts[0].trim();
    const modifier = (parts[1] ?? '').trim();

    if (!eventName) {
        return {eventName: '', handlerFunc: null};
    }

    const handlerFunc = (event: Event) => {
        console.warn('[DOMBinder] Event handler triggered:', {
            eventName,
            modifier,
            eventType: event.type,
            target: (event.target as HTMLElement)?.tagName,
            currentTarget: (event.currentTarget as HTMLElement)?.tagName
        });

        event.preventDefault();

        let payload: ActionPayload;
        try {
            payload = JSON.parse(atob(encodedPayload)) as ActionPayload;
        } catch (e) {
            console.error('DOMBinder: Could not decode action payload.', {encodedPayload, element: el, error: e});
            return;
        }

        // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- payload.a may be undefined at runtime
        const resolvedArgs = payload.a ?? [];
        const method = (el.getAttribute('data-pp-action-method') ?? 'POST').toUpperCase();

        if (modifier === 'remote') {
            console.warn('[DOMBinder] Calling onServerAction:', { actionName: payload.f, method });
            callbacks.onServerAction(payload.f, el, event, method, resolvedArgs);
        } else if (modifier === 'helper') {
            const helper = helperRegistry.get(payload.f);
            if (helper) {
                // Helpers always receive (el, event, ...stringArgs)
                // For $event in args, use event.type as the string value
                const args = resolvedArgs.map(a => (a.t === 'e' ? event.type : String(a.v)));
                helper(el, event, ...args);
            } else {
                console.warn(`DOMBinder: Unknown p-on helper action: "${payload.f}"`);
            }
        } else if (isCustomEvent && modifier === '') {
            // Custom event without modifier - check PageContext first, then fall back to server action
            const pageContext = getGlobalPageContext();
            if (pageContext.hasFunction(payload.f)) {
                try {
                    // Pass raw event first (for PK wrapper scoping), then resolved args
                    const args = resolveArgsWithEvent(resolvedArgs, event);
                    const result = pageContext.getFunction(payload.f)?.(event, ...args);

                    // Check if result is an action descriptor
                    if (isActionDescriptor(result)) {
                        handleAction(result, el, event).catch((err: unknown) => {
                            console.error('[DOMBinder] Action execution failed:', err);
                        });
                    }
                } catch (error) {
                    console.error(`[DOMBinder] Error in page handler "${payload.f}":`, error);
                }
            } else {
                // Provide helpful error message with suggestions (no server fallback)
                const available = pageContext.getExportedFunctions();
                const suggestion = findClosestMatch(payload.f, available);

                let message = `[DOMBinder] Function "${payload.f}" not found for p-event handler.`;
                message += ` Did you forget to export it?`;
                if (suggestion) {
                    message += ` Did you mean "${suggestion}"?`;
                }
                if (available.length > 0) {
                    message += ` Available functions: ${available.join(', ')}`;
                }
                console.warn(message);
            }
        } else if (modifier === '') {
            // Local page function call (p-on:click="handleClick" without modifier)
            // Supports scoped partial functions and cross-partial @partial.fn() syntax
            const pageContext = getGlobalPageContext();
            const {partialName: explicitPartial, fnName} = parseFunctionReference(payload.f);

            if (explicitPartial) {
                // Explicit cross-partial call: @modal-wrapper.open()
                // Broadcast to ALL instances of that partial
                const fns = pageContext.getFunctionsByPartialName(explicitPartial, fnName);
                if (fns.length > 0) {
                    // Pass raw event first (for PK wrapper scoping), then resolved args
                    const args = resolveArgsWithEvent(resolvedArgs, event);
                    for (const fn of fns) {
                        try {
                            const result = fn(event, ...args);
                            if (isActionDescriptor(result)) {
                                handleAction(result, el, event).catch((err: unknown) => {
                                    console.error(`[DOMBinder] Action execution failed for @${explicitPartial}.${fnName}:`, err);
                                });
                            }
                        } catch (error) {
                            console.error(`[DOMBinder] Error in @${explicitPartial}.${fnName}:`, error);
                        }
                    }
                } else {
                    // Provide helpful error message
                    const available = pageContext.getRegisteredPartialNames();
                    const suggestion = findClosestMatch(explicitPartial, available);

                    let message = `[DOMBinder] Partial "${explicitPartial}" not found or has no function "${fnName}".`;
                    if (suggestion) {
                        message += ` Did you mean "@${suggestion}"?`;
                    }
                    if (available.length > 0) {
                        message += ` Registered partials: ${available.join(', ')}`;
                    }
                    console.warn(message);
                }
            } else {
                // Implicit scope: find current partial from DOM
                const partialId = findPartialScope(el);
                let fn: ((...args: unknown[]) => unknown) | undefined;

                if (partialId) {
                    // Try scoped lookup first
                    fn = pageContext.getScopedFunction(fnName, partialId);
                }

                if (!fn) {
                    // Fallback to global (page-level functions, backwards compatibility)
                    fn = pageContext.getFunction(fnName);
                }

                if (fn) {
                    try {
                        // Pass raw event first (for PK wrapper scoping), then resolved args
                        const args = resolveArgsWithEvent(resolvedArgs, event);
                        const result = fn(event, ...args);

                        // Check if result is an action descriptor
                        if (isActionDescriptor(result)) {
                            handleAction(result, el, event).catch((err: unknown) => {
                                console.error(`[DOMBinder] Action execution failed for "${fnName}":`, err);
                            });
                        }
                    } catch (error) {
                        console.error(`[DOMBinder] Error in page handler "${fnName}":`, error);
                    }
                } else {
                    // Provide helpful error message with suggestions
                    const available = pageContext.getExportedFunctions();
                    const suggestion = findClosestMatch(fnName, available);

                    let message = `[DOMBinder] Function "${fnName}" not found.`;
                    if (partialId) {
                        message += ` (searched partial scope and global)`;
                    }
                    message += ` Did you forget to export it?`;
                    if (suggestion) {
                        message += ` Did you mean "${suggestion}"?`;
                    }
                    if (available.length > 0) {
                        message += ` Available functions: ${available.join(', ')}`;
                    }
                    console.warn(message);
                }
            }
        } else {
            console.warn(`[DOMBinder] Unsupported modifier "${modifier}" for p-${isCustomEvent ? 'event' : 'on'}:${key}`);
        }
    };

    return {eventName, handlerFunc};
}

function addHandler(handlers: Map<string, EventHandlerFunc[]>, eventName: string, fn: EventHandlerFunc): void {
    if (!handlers.has(eventName)) {
        handlers.set(eventName, []);
    }
    handlers.get(eventName)?.push(fn);
}

/**
 * Creates a DOMBinder instance
 */
export function createDOMBinder(helperRegistry: HelperRegistry, callbacks: DOMBinderCallbacks): DOMBinder {
    const onNavigateLinkClick = (ev: MouseEvent) => {
        const linkEl = ev.currentTarget as HTMLAnchorElement | null;
        const href = linkEl?.getAttribute('href');

        if (!href) {
            return;
        }

        // Block dangerous schemes entirely
        if (isBlockedScheme(href)) {
            ev.preventDefault();
            console.warn('DOMBinder: Blocked navigation to dangerous URI scheme:', href);
            return;
        }

        // Let browser handle native schemes (tel:, mailto:, etc.)
        if (isNativeScheme(href)) {
            return;
        }

        // Normal URL - use SPA navigation
        ev.preventDefault();
        callbacks.onNavigate(href, ev);
    };

    function bindLinks(rootElement: HTMLElement): void {
        rootElement.querySelectorAll<HTMLAnchorElement>('a[piko:a]').forEach(linkEl => {
            linkEl.removeEventListener('click', onNavigateLinkClick);
            linkEl.addEventListener('click', onNavigateLinkClick);
        });
    }

    function bindActions(rootElement: HTMLElement): void {
        rootElement.querySelectorAll<HTMLElement>('*').forEach(el => {
            if (el.hasAttribute(BOUND_MARKER)) {
                return;
            }

            const handlers = new Map<string, EventHandlerFunc[]>();
            let hasBound = false;

            for (const {name: attrName, value: attrValue} of Array.from(el.attributes)) {
                let result: HandlerResult | null = null;

                if (attrName.startsWith('p-on:')) {
                    result = createActionHandler(attrName.slice(P_ON_PREFIX_LEN), attrValue, false, el, helperRegistry, callbacks);
                } else if (attrName.startsWith('p-event:')) {
                    result = createActionHandler(attrName.slice(P_EVENT_PREFIX_LEN), attrValue, true, el, helperRegistry, callbacks);
                }

                if (result?.handlerFunc) {
                    addHandler(handlers, result.eventName, result.handlerFunc);
                    hasBound = true;
                }
            }

            if (el.hasAttribute('p-modal:selector')) {
                addHandler(handlers, 'click', createModalHandler(el, callbacks));
                hasBound = true;
            }

            handlers.forEach((funcs, eventName) => {
                el.addEventListener(eventName, event => funcs.forEach(fn => fn(event)));
            });

            if (hasBound) {
                el.setAttribute(BOUND_MARKER, 'true');
            }
        });
    }

    return {
        bind: (root: HTMLElement) => {
            bindLinks(root);
            bindActions(root);
        },
        bindLinks,
        bindActions
    };
}
