/**
 * ModuleLoader - Handles loading ES modules and lazy loading via IntersectionObserver
 */

export interface ModuleLoader {
    /** Load module scripts from a parsed document */
    loadFromDocument(doc: Document): void;

    /** Load module scripts from a parsed document and await their execution */
    loadFromDocumentAsync(doc: Document): Promise<void>;

    /** Observe pp-module elements for lazy loading */
    observeLazyModules(): void;

    /** Dynamically load a module from an element */
    loadDynamically(moduleEl: HTMLElement): void;

    /** Check if a module has already been loaded */
    hasLoaded(src: string): boolean;

    /** Get the set of loaded module URLs */
    getLoadedModules(): Set<string>;
}

/**
 * Creates a ModuleLoader instance
 */
export function createModuleLoader(): ModuleLoader {
    const loadedModuleScripts = new Set<string>();

    function loadScript(src: string): void {
        if (loadedModuleScripts.has(src)) {
            return;
        }
        loadedModuleScripts.add(src);
        const newScript = document.createElement('script');
        newScript.type = 'module';
        newScript.src = src;
        document.body.appendChild(newScript);
    }

    return {
        loadFromDocument(doc: Document) {
            // Load standard module scripts
            const moduleScripts = doc.querySelectorAll('script[type="module"]');
            moduleScripts.forEach(scriptEl => {
                const src = scriptEl.getAttribute('src');
                if (src) {
                    loadScript(src);
                }
            });

            // Load pp-module elements
            const customModules = doc.querySelectorAll('pp-module[src]');
            customModules.forEach(ppEl => {
                const src = ppEl.getAttribute('src');
                if (src) {
                    loadScript(src);
                    ppEl.remove();
                }
            });
        },

        async loadFromDocumentAsync(doc: Document) {
            const loadPromises: Promise<unknown>[] = [];

            // Load standard module scripts
            const moduleScripts = doc.querySelectorAll('script[type="module"]');
            moduleScripts.forEach(scriptEl => {
                const src = scriptEl.getAttribute('src');
                if (src && !loadedModuleScripts.has(src)) {
                    loadedModuleScripts.add(src);
                    // Use dynamic import to await module execution
                    loadPromises.push(
                        import(/* webpackIgnore: true */ src).catch(err => {
                            console.error(`ModuleLoader: Failed to load module ${src}:`, err);
                        })
                    );
                }
            });

            // Load pp-module elements
            const customModules = doc.querySelectorAll('pp-module[src]');
            customModules.forEach(ppEl => {
                const src = ppEl.getAttribute('src');
                if (src && !loadedModuleScripts.has(src)) {
                    loadedModuleScripts.add(src);
                    loadPromises.push(
                        import(/* webpackIgnore: true */ src).catch(err => {
                            console.error(`ModuleLoader: Failed to load module ${src}:`, err);
                        })
                    );
                    ppEl.remove();
                }
            });

            // Wait for all modules to load and execute
            await Promise.all(loadPromises);
        },

        observeLazyModules() {
            const moduleElements = document.querySelectorAll('pp-module');
            if (!moduleElements.length) {
                return;
            }

            const intersectionObserver = new IntersectionObserver(
                observedEntries => {
                    for (const entry of observedEntries) {
                        if (entry.isIntersecting) {
                            const moduleEl = entry.target as HTMLElement;
                            this.loadDynamically(moduleEl);
                            intersectionObserver.unobserve(moduleEl);
                        }
                    }
                },
                {
                    root: null,
                    rootMargin: '300px 0px',
                    threshold: 0
                }
            );

            moduleElements.forEach(el => intersectionObserver.observe(el));
        },

        loadDynamically(moduleEl: HTMLElement) {
            const compName = moduleEl.getAttribute('component');
            const moduleSrc = moduleEl.getAttribute('src');

            if (!compName || !moduleSrc) {
                return;
            }

            if (loadedModuleScripts.has(moduleSrc)) {
                return;
            }

            loadedModuleScripts.add(moduleSrc);

            import(/* webpackIgnore: true */ moduleSrc)
                .then(() => {
                    // Module loaded successfully
                })
                .catch(err => {
                    console.error(`ModuleLoader: Failed to load module <${compName}>:`, err);
                });
        },

        hasLoaded(src: string) {
            return loadedModuleScripts.has(src);
        },

        getLoadedModules() {
            return loadedModuleScripts;
        }
    };
}

/**
 * Initialise module loader with existing scripts on page
 */
export function initModuleLoaderFromPage(loader: ModuleLoader): void {
    const initialScripts = document.querySelectorAll('script[type="module"]');
    const loadedModules = loader.getLoadedModules();

    initialScripts.forEach(scriptEl => {
        const src = scriptEl.getAttribute('src');
        if (src) {
            loadedModules.add(src);
        }
    });
}
