/**
 * PK Events - Dispatch and listen helpers for PK/PKC communication
 *
 * Provides utilities for cross-component event communication using
 * CustomEvents with automatic element resolution.
 *
 * @example
 * ```typescript
 * // Dispatch event to a PKC by ref
 * dispatch('cart-icon', 'item:added', { productId: 123, quantity: 1 });
 *
 * // Listen for events from a PKC
 * const unsub = listen('cart-button', 'cart:updated', (event) => {
 *     console.log('Cart updated:', event.detail);
 *     reloadPartial('cart-summary');
 * });
 *
 * // Listen for any event on document
 * const unsub = listen('*', 'user:login', (event) => {
 *     console.log('User logged in');
 * });
 *
 * // Cleanup
 * onCleanup(unsub);
 * ```
 */

// ============================================================================
// Types
// ============================================================================

export interface DispatchOptions {
    /** Whether the event bubbles up through the DOM (default: true) */
    bubbles?: boolean;
    /** Whether the event can cross shadow DOM boundary (default: true) */
    composed?: boolean;
}

export type EventListener = (event: CustomEvent) => void;

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Resolves a target specification to an Element
 *
 * Supports:
 * - '*' -> document
 * - p-ref name -> element with matching p-ref attribute
 * - CSS selector -> element matching selector
 * - HTMLElement -> returns as-is
 */
function resolveTarget(target: string | HTMLElement | '*'): Element | Document | null {
    if (target === '*') {
        return document;
    }

    if (target instanceof HTMLElement) {
        return target;
    }

    // Try p-ref first
    const byRef = document.querySelector(`[p-ref="${target}"]`);
    if (byRef) {
        return byRef;
    }

    // Fall back to CSS selector
    return document.querySelector(target);
}

// ============================================================================
// Exported Functions
// ============================================================================

/**
 * Dispatches a custom event to a target element
 *
 * Supports targeting by:
 * - p-ref name (e.g., 'cart-icon')
 * - CSS selector (e.g., '#myElement', '.my-class')
 * - HTMLElement reference
 *
 * @param target - Target specification (p-ref name, selector, or element)
 * @param eventName - Event name (e.g., 'item:added', 'cart:updated')
 * @param detail - Event detail payload
 * @param options - Event options (bubbles, composed)
 *
 * @example
 * ```typescript
 * // Dispatch to element by p-ref
 * dispatch('cart-icon', 'item:added', { count: 5 });
 *
 * // Dispatch to element by selector
 * dispatch('#my-component', 'update', { value: 42 });
 *
 * // Dispatch with custom options
 * dispatch('modal', 'close', null, { bubbles: false });
 * ```
 */
export function dispatch(
    target: string | HTMLElement,
    eventName: string,
    detail?: unknown,
    options?: DispatchOptions
): void {
    const el = resolveTarget(target);

    if (!el) {
        console.warn(`[pk] dispatch: target "${target}" not found`);
        return;
    }

    const event = new CustomEvent(eventName, {
        detail,
        bubbles: options?.bubbles ?? true,
        composed: options?.composed ?? true
    });

    el.dispatchEvent(event);
}

/**
 * Listens for custom events on a target element
 *
 * Supports targeting by:
 * - '*' for document-wide listening
 * - p-ref name (e.g., 'cart-icon')
 * - CSS selector (e.g., '#myElement', '.my-class')
 * - HTMLElement reference
 *
 * @param target - Target specification ('*' for document, p-ref name, selector, or element)
 * @param eventName - Event name to listen for
 * @param callback - Event handler function
 * @returns Unsubscribe function to remove the listener
 *
 * @example
 * ```typescript
 * // Listen on specific element
 * const unsub = listen('cart-button', 'product:added', (e) => {
 *     console.log('Product added:', e.detail.productId);
 * });
 *
 * // Listen on document (catches all bubbling events)
 * const unsub = listen('*', 'user:logout', () => {
 *     window.location.href = '/login';
 * });
 *
 * // Cleanup when element is removed
 * onCleanup(unsub);
 * ```
 */
export function listen(
    target: string | HTMLElement | '*',
    eventName: string,
    callback: EventListener
): () => void {
    const el = resolveTarget(target);

    if (!el) {
        console.warn(`[pk] listen: target "${target}" not found`);
        return () => {
            // No-op cleanup
        };
    }

    const handler = (e: Event): void => {
        callback(e as CustomEvent);
    };

    el.addEventListener(eventName, handler);

    return () => {
        el.removeEventListener(eventName, handler);
    };
}

/**
 * Listens for an event once, then automatically unsubscribes
 *
 * @param target - Target specification
 * @param eventName - Event name to listen for
 * @param callback - Event handler function
 * @returns Unsubscribe function (useful if you want to cancel before event fires)
 *
 * @example
 * ```typescript
 * // Wait for a single event
 * listenOnce('modal', 'closed', () => {
 *     console.log('Modal was closed');
 * });
 * ```
 */
export function listenOnce(
    target: string | HTMLElement | '*',
    eventName: string,
    callback: EventListener
): () => void {
    const unsubscribe = listen(target, eventName, (event) => {
        unsubscribe();
        callback(event);
    });

    return () => {
        unsubscribe();
    };
}

/**
 * Creates a promise that resolves when an event is received
 *
 * Useful for async/await patterns with events.
 *
 * @param target - Target specification
 * @param eventName - Event name to wait for
 * @param timeout - Optional timeout in ms (rejects if exceeded)
 * @returns Promise that resolves with the event detail
 *
 * @example
 * ```typescript
 * // Wait for modal to close
 * await waitForEvent('modal', 'closed');
 *
 * // Wait with timeout
 * try {
 *     const result = await waitForEvent('form', 'validated', 5000);
 * } catch (e) {
 *     console.log('Validation timed out');
 * }
 * ```
 */
export function waitForEvent<T = unknown>(
    target: string | HTMLElement | '*',
    eventName: string,
    timeout?: number
): Promise<T> {
    return new Promise((resolve, reject) => {
        let timeoutId: ReturnType<typeof setTimeout> | null = null;

        const unsubscribe = listenOnce(target, eventName, (event) => {
            if (timeoutId) {
                clearTimeout(timeoutId);
            }
            resolve(event.detail as T);
        });

        if (timeout !== undefined && timeout > 0) {
            timeoutId = setTimeout(() => {
                unsubscribe();
                reject(new Error(`Timeout waiting for event "${eventName}"`));
            }, timeout);
        }
    });
}
