/**
 * LifecycleManager - Manages lifecycle callback registration and execution
 */

import type {LifecycleCallbacks, UpdatedCallback, VoidCallback} from "../types";

export interface LifecycleManager {
    /** Add a callback to be run on connected */
    addOnConnected(callback: VoidCallback): void;

    /** Add a callback to be run on disconnected */
    addOnDisconnected(callback: VoidCallback): void;

    /** Add a callback to be run before render */
    addOnBeforeRender(callback: VoidCallback): void;

    /** Add a callback to be run after render */
    addOnAfterRender(callback: VoidCallback): void;

    /** Add a callback to be run after state update */
    addOnUpdated(callback: UpdatedCallback): void;

    /** Execute connected lifecycle */
    executeConnected(): void;

    /** Execute disconnected lifecycle */
    executeDisconnected(): void;

    /** Execute before render lifecycle */
    executeBeforeRender(): void;

    /** Execute after render lifecycle */
    executeAfterRender(): void;

    /** Execute updated lifecycle with changed properties */
    executeUpdated(changedProperties: Set<string>): void;

    /** Reset connected state (for reconnection handling) */
    resetConnectedState(): void;

    /** Check if initial connection has occurred */
    hasConnectedOnce(): boolean;
}

export interface LifecycleManagerOptions {
    /** Instance callbacks from the component class */
    instanceCallbacks: LifecycleCallbacks;

    /** Function to get context callbacks from $$ctx */
    getContextCallbacks: () => LifecycleCallbacks | undefined;
}

/**
 * Creates a LifecycleManager instance for managing lifecycle callback registration and execution
 */
export function createLifecycleManager(options: LifecycleManagerOptions): LifecycleManager {
    const {instanceCallbacks, getContextCallbacks} = options;

    const onConnectedCallbacks: VoidCallback[] = [];
    const onDisconnectedCallbacks: VoidCallback[] = [];
    const onBeforeRenderCallbacks: VoidCallback[] = [];
    const onAfterRenderCallbacks: VoidCallback[] = [];
    const onUpdatedCallbacks: UpdatedCallback[] = [];

    let connectedOnce = false;

    return {
        addOnConnected(callback: VoidCallback): void {
            onConnectedCallbacks.push(callback);
        },

        addOnDisconnected(callback: VoidCallback): void {
            onDisconnectedCallbacks.push(callback);
        },

        addOnBeforeRender(callback: VoidCallback): void {
            onBeforeRenderCallbacks.push(callback);
        },

        addOnAfterRender(callback: VoidCallback): void {
            onAfterRenderCallbacks.push(callback);
        },

        addOnUpdated(callback: UpdatedCallback): void {
            onUpdatedCallbacks.push(callback);
        },

        executeConnected(): void {
            if (connectedOnce) {
                return;
            }
            connectedOnce = true;

            // Execute registered callbacks
            onConnectedCallbacks.forEach((cb) => cb());

            // Execute instance callback (protected method override)
            instanceCallbacks.onConnected?.();

            // Execute context callback (from $$ctx)
            const contextCallbacks = getContextCallbacks();
            contextCallbacks?.onConnected?.();
        },

        executeDisconnected(): void {
            // Execute instance callback first
            instanceCallbacks.onDisconnected?.();

            // Execute context callback
            const contextCallbacks = getContextCallbacks();
            contextCallbacks?.onDisconnected?.();

            // Execute registered callbacks
            onDisconnectedCallbacks.forEach((cb) => cb());
        },

        executeBeforeRender(): void {
            // Execute registered callbacks
            onBeforeRenderCallbacks.forEach((cb) => cb());

            // Execute instance callback
            instanceCallbacks.onBeforeRender?.();

            // Execute context callback
            const contextCallbacks = getContextCallbacks();
            contextCallbacks?.onBeforeRender?.();
        },

        executeAfterRender(): void {
            // Execute registered callbacks
            onAfterRenderCallbacks.forEach((cb) => cb());

            // Execute instance callback
            instanceCallbacks.onAfterRender?.();

            // Execute context callback
            const contextCallbacks = getContextCallbacks();
            contextCallbacks?.onAfterRender?.();
        },

        executeUpdated(changedProperties: Set<string>): void {
            // Execute registered callbacks
            onUpdatedCallbacks.forEach((cb) => cb(changedProperties));

            // Execute instance callback
            instanceCallbacks.onUpdated?.(changedProperties);

            // Execute context callback
            const contextCallbacks = getContextCallbacks();
            contextCallbacks?.onUpdated?.(changedProperties);
        },

        resetConnectedState(): void {
            connectedOnce = false;
        },

        hasConnectedOnce(): boolean {
            return connectedOnce;
        },
    };
}
