/**
 * LoaderUI - Progress bar indicator for navigation and loading states
 */

const LOADER_FADE_MS = 300;
const PROGRESS_MIN = 0;
const PROGRESS_MAX = 100;

export interface LoaderUI {
    /** Show the loader bar */
    show(): void;

    /** Hide the loader bar with fade animation */
    hide(): void;

    /** Update the progress bar percentage (0-100) */
    setProgress(percent: number): void;

    /** Remove the loader element from DOM */
    destroy(): void;
}

export interface LoaderUIOptions {
    /** Colour of the progress bar */
    color?: string;

    /** Fade duration in milliseconds */
    fadeMs?: number;

    /** Container element to append loader to */
    container?: HTMLElement;
}

/**
 * Creates a LoaderUI instance
 */
export function createLoaderUI(options: LoaderUIOptions = {}): LoaderUI {
    const {
        color = '#29e',
        fadeMs = LOADER_FADE_MS,
        container = document.body
    } = options;

    const el = document.createElement('div');
    el.id = 'ppf-loader-bar';
    el.style.cssText = [
        'position:fixed',
        'top:0',
        'left:0',
        'width:0%',
        'height:2px',
        `background:${color}`,
        'transition:width .2s',
        'z-index:9999',
        'pointer-events:none',
        'display:none',
    ].join(';');
    container.appendChild(el);

    return {
        show() {
            el.style.display = 'block';
            el.style.width = '0%';
        },

        hide() {
            el.style.width = '100%';
            setTimeout(() => {
                el.style.width = '0%';
                el.style.display = 'none';
            }, fadeMs);
        },

        setProgress(percent: number) {
            let pct = percent;
            if (pct < PROGRESS_MIN) {
                pct = PROGRESS_MIN;
            }
            if (pct > PROGRESS_MAX) {
                pct = PROGRESS_MAX;
            }
            el.style.display = 'block';
            el.style.width = `${pct}%`;
        },

        destroy() {
            el.remove();
        }
    };
}
