import {type PPHelper, RegisterHelper} from '@/core';

const findFormToSubmit = (element: HTMLElement, formSelector?: string): HTMLFormElement | null => {
    if (formSelector) {
        const form = document.querySelector<HTMLFormElement>(formSelector);

        if (!form) {
            console.error(`PPFramework Helper 'submitForm' failed: Could not find any form matching the selector "${formSelector}".`, {
                triggeringElement: element,
            });
            return null;
        }
        return form;
    }

    const parentForm = element.closest<HTMLFormElement>('form');

    if (!parentForm) {
        console.warn('p-on:click.helper="submitForm" was used without a selector, but no parent form could be found.', {
            triggeringElement: element,
        });
        return null;
    }

    return parentForm;
};

const submitFormHelper: PPHelper = (element: HTMLElement, _event: Event, ...args: string[]) => {
    const formSelector = args[0];
    const formToSubmit = findFormToSubmit(element, formSelector);
    formToSubmit?.requestSubmit();
};

RegisterHelper('submitForm', submitFormHelper);
RegisterHelper('submitModalForm', submitFormHelper);
