/**
 * PageContext - Manages ES module exports from PK page scripts
 *
 * Enables p-on:click="handleClick" to call exported functions from page scripts.
 * DOMBinder routes no-modifier handlers to this context for function lookup.
 *
 * Supports scoped function resolution for partials:
 * - Functions are stored per-partial using the partial's hashed ID
 * - Friendly partial names (e.g., "modal-wrapper") map to hashed IDs
 * - `@partial-name.fn()` syntax broadcasts to all instances of a partial
 */

export interface PageContext {
    /** Get an exported function by name (searches global then all scopes) */
    getFunction(name: string): ((...args: unknown[]) => unknown) | undefined;

    /** Check if a function is exported */
    hasFunction(name: string): boolean;

    /** Get all exported function names (for error suggestions) */
    getExportedFunctions(): string[];

    /** Clear the current context (called on navigation) */
    clear(): void;

    /** Load exports from an ES module URL, optionally scoped to a partial */
    loadModule(url: string, partialName?: string): Promise<void>;

    /** Set exports directly (for testing or pre-loaded modules) */
    setExports(exports: Record<string, unknown>): void;

    /** Get function from a specific partial's scope by its hashed ID */
    getScopedFunction(name: string, partialId: string): ((...args: unknown[]) => unknown) | undefined;

    /** Get all functions matching a name across all instances of a partial by friendly name */
    getFunctionsByPartialName(partialName: string, fnName: string): ((...args: unknown[]) => unknown)[];

    /** Register a partial instance (called when partial appears in DOM) */
    registerPartialInstance(partialName: string, partialId: string): void;

    /** Get all registered partial names (for error suggestions) */
    getRegisteredPartialNames(): string[];
}

export interface PageContextOptions {
    onError?: (error: Error, context: string) => void;
    onModuleLoaded?: (url: string, exports: string[]) => void;
}

/**
 * Creates a new PageContext instance with scoped function support
 */
export function createPageContext(options: PageContextOptions = {}): PageContext {
    // Global exports (page-level functions, backwards compatibility)
    let globalExports: Record<string, unknown> = {};

    // Scoped exports keyed by partial ID (hashed name like "partials_modal_wrapper_b435bc79")
    let scopedExports: Record<string, Record<string, unknown>> = {};

    // Map friendly partial names to their hashed IDs (supports multiple instances)
    let nameToIds: Record<string, string[]> = {};

    return {
        getFunction(name: string) {
            // First check global exports (page-level functions)
            const globalFn = globalExports[name];
            if (typeof globalFn === 'function') {
                return globalFn as (...args: unknown[]) => unknown;
            }
            // Fallback: search all scoped exports (backwards compatibility)
            for (const scope of Object.values(scopedExports)) {
                const fn = scope[name];
                if (typeof fn === 'function') {
                    return fn as (...args: unknown[]) => unknown;
                }
            }
            return undefined;
        },

        hasFunction(name: string) {
            if (typeof globalExports[name] === 'function') {
                return true;
            }
            for (const scope of Object.values(scopedExports)) {
                if (typeof scope[name] === 'function') {
                    return true;
                }
            }
            return false;
        },

        getExportedFunctions() {
            const fns = new Set<string>();
            // Add global functions
            for (const key of Object.keys(globalExports)) {
                if (typeof globalExports[key] === 'function') {
                    fns.add(key);
                }
            }
            // Add scoped functions
            for (const scope of Object.values(scopedExports)) {
                for (const key of Object.keys(scope)) {
                    if (typeof scope[key] === 'function') {
                        fns.add(key);
                    }
                }
            }
            return Array.from(fns);
        },

        clear() {
            globalExports = {};
            scopedExports = {};
            nameToIds = {};
        },

        async loadModule(url: string, partialName?: string) {
            try {
                // Dynamic import of the page module
                // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
                const module = await import(/* @vite-ignore */ url);

                if (partialName) {
                    // Extract partial ID from module if available, otherwise derive from URL
                    // The partial ID follows the pattern in the URL: /_pp/assets/pk-js/partials/{name}.js
                    // We use the partialName as the key for now, but modules could export __PARTIAL_ID__
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-member-access
                    const partialId = (module.__PARTIAL_ID__ as string) ?? partialName;

                    // Store in scoped exports
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
                    scopedExports[partialId] = {...(scopedExports[partialId] ?? {}), ...module};

                    // Register the partial instance
                    this.registerPartialInstance(partialName, partialId);
                } else {
                    // Page-level script goes to global exports
                    // eslint-disable-next-line @typescript-eslint/no-unsafe-assignment
                    globalExports = {...globalExports, ...module};
                }

                const exportedFns = this.getExportedFunctions();
                options.onModuleLoaded?.(url, exportedFns);
            } catch (error) {
                if (options.onError) {
                    options.onError(error as Error, `loadModule(${url})`);
                } else {
                    console.error('[PageContext] Failed to load module:', {
                        url,
                        error
                    });
                }
            }
        },

        setExports(newExports: Record<string, unknown>) {
            // Merge with global exports for backwards compatibility
            globalExports = {...globalExports, ...newExports};
        },

        getScopedFunction(name: string, partialId: string) {
            const scope = scopedExports[partialId];
            if (!scope) {
                return undefined;
            }
            const fn = scope[name];
            if (typeof fn === 'function') {
                return fn as (...args: unknown[]) => unknown;
            }
            return undefined;
        },

        getFunctionsByPartialName(partialName: string, fnName: string) {
            const ids = nameToIds[partialName] ?? [];
            const fns: ((...args: unknown[]) => unknown)[] = [];
            for (const id of ids) {
                const scope = scopedExports[id];
                if (scope) {
                    const fn = scope[fnName];
                    if (typeof fn === 'function') {
                        fns.push(fn as (...args: unknown[]) => unknown);
                    }
                }
            }
            return fns;
        },

        registerPartialInstance(partialName: string, partialId: string) {
            if (!nameToIds[partialName]) {
                nameToIds[partialName] = [];
            }
            if (!nameToIds[partialName].includes(partialId)) {
                nameToIds[partialName].push(partialId);
            }
        },

        getRegisteredPartialNames() {
            return Object.keys(nameToIds);
        }
    };
}

// Global singleton instance
let globalPageContext: PageContext | null = null;

/**
 * Gets the global PageContext instance (creates one if needed)
 */
export function getGlobalPageContext(): PageContext {
    globalPageContext ??= createPageContext();
    return globalPageContext;
}

/**
 * Resets the global PageContext (for testing)
 */
export function resetGlobalPageContext(): void {
    globalPageContext?.clear();
    globalPageContext = null;
}

/**
 * Finds the closest matching function name using Levenshtein distance
 * Returns the best match if within threshold, undefined otherwise
 */
export function findClosestMatch(target: string, candidates: string[], threshold = 3): string | undefined {
    if (candidates.length === 0) {
        return undefined;
    }

    let bestMatch: string | undefined;
    let bestDistance = Infinity;

    for (const candidate of candidates) {
        const distance = levenshteinDistance(target.toLowerCase(), candidate.toLowerCase());
        if (distance < bestDistance && distance <= threshold) {
            bestDistance = distance;
            bestMatch = candidate;
        }
    }

    return bestMatch;
}

/**
 * Calculates Levenshtein distance between two strings
 */
function levenshteinDistance(a: string, b: string): number {
    if (a.length === 0) {
        return b.length;
    }
    if (b.length === 0) {
        return a.length;
    }

    const matrix: number[][] = [];

    // Initialise first column
    for (let i = 0; i <= b.length; i++) {
        matrix[i] = [i];
    }

    // Initialise first row
    for (let j = 0; j <= a.length; j++) {
        matrix[0][j] = j;
    }

    // Fill in the rest
    for (let i = 1; i <= b.length; i++) {
        for (let j = 1; j <= a.length; j++) {
            if (b.charAt(i - 1) === a.charAt(j - 1)) {
                matrix[i][j] = matrix[i - 1][j - 1];
            } else {
                matrix[i][j] = Math.min(
                    matrix[i - 1][j - 1] + 1, // substitution
                    matrix[i][j - 1] + 1,     // insertion
                    matrix[i - 1][j] + 1      // deletion
                );
            }
        }
    }

    return matrix[b.length][a.length];
}

// Expose on window for debugging and external access
if (typeof window !== 'undefined') {
    // eslint-disable-next-line @typescript-eslint/naming-convention -- Double underscore prefix indicates internal/debugging property
    (window as unknown as {__pikoPageContext: PageContext}).__pikoPageContext = getGlobalPageContext();
}
