/**
 * CSRFUtils - CSRF token utilities for page-wide protection
 *
 * Reads CSRF tokens from meta tags (Rails/Django/Laravel pattern).
 * This provides a clean, standard way to include CSRF protection across
 * all actions without requiring per-element attributes.
 *
 * The backend renders tokens in the page head:
 * ```html
 * <meta name="csrf-token" content="action-token-here">
 * <meta name="csrf-ephemeral" content="ephemeral-token-here">
 * ```
 */

// ============================================================================
// Constants
// ============================================================================

/** Meta tag name for the signed action token */
const CSRF_TOKEN_META_NAME = 'csrf-token';

/** Meta tag name for the ephemeral token */
const CSRF_EPHEMERAL_META_NAME = 'csrf-ephemeral';

// ============================================================================
// Functions
// ============================================================================

/**
 * Reads the CSRF action token from the meta tag
 *
 * This is the signed token that includes the cookie binding,
 * ephemeral token, timestamp, and HMAC signature.
 *
 * @returns The CSRF action token, or null if not found
 *
 * @example
 * ```typescript
 * const token = getCSRFTokenFromMeta();
 * if (token) {
 *     headers['X-CSRF-Action-Token'] = token;
 * }
 * ```
 */
export function getCSRFTokenFromMeta(): string | null {
    return document.querySelector<HTMLMetaElement>(`meta[name="${CSRF_TOKEN_META_NAME}"]`)?.content ?? null;
}

/**
 * Reads the CSRF ephemeral token from the meta tag
 *
 * This is the raw ephemeral token that needs to be sent in the
 * request body or query parameters.
 *
 * @returns The CSRF ephemeral token, or null if not found
 *
 * @example
 * ```typescript
 * const ephemeral = getCSRFEphemeralFromMeta();
 * if (ephemeral) {
 *     body._csrf_ephemeral_token = ephemeral;
 * }
 * ```
 */
export function getCSRFEphemeralFromMeta(): string | null {
    return document.querySelector<HTMLMetaElement>(`meta[name="${CSRF_EPHEMERAL_META_NAME}"]`)?.content ?? null;
}

/**
 * Gets both CSRF tokens from meta tags
 *
 * @returns Object with actionToken and ephemeralToken (both may be null)
 *
 * @example
 * ```typescript
 * const { actionToken, ephemeralToken } = getCSRFTokensFromMeta();
 * ```
 */
export function getCSRFTokensFromMeta(): {
    actionToken: string | null;
    ephemeralToken: string | null;
} {
    return {
        actionToken: getCSRFTokenFromMeta(),
        ephemeralToken: getCSRFEphemeralFromMeta()
    };
}
