/**
 * ErrorDisplay - Shows error messages to the user
 */

const ERROR_DISPLAY_MS = 5000;

export interface ErrorDisplay {
    /** Display an error message */
    show(message: string): void;

    /** Clear any displayed error */
    clear(): void;
}

export interface ErrorDisplayOptions {
    /** Duration to show error in milliseconds */
    displayMs?: number;

    /** Container element to append error to */
    container?: HTMLElement;
}

/**
 * Creates an ErrorDisplay instance
 */
export function createErrorDisplay(options: ErrorDisplayOptions = {}): ErrorDisplay {
    const {
        displayMs = ERROR_DISPLAY_MS,
        container = document.body
    } = options;

    let currentElement: HTMLElement | null = null;
    let timeoutId: ReturnType<typeof setTimeout> | null = null;

    return {
        show(message: string) {
            // Reuse existing element if present
            const existingEl = document.getElementById('ppf-error-message');
            if (existingEl) {
                existingEl.textContent = message;
                return;
            }

            // Clear any existing timeout
            if (timeoutId) {
                clearTimeout(timeoutId);
            }

            const errEl = document.createElement('div');
            errEl.id = 'ppf-error-message';
            errEl.style.cssText = [
                'position:fixed',
                'top:60px',
                'left:50%',
                'transform:translateX(-50%)',
                'background:#f44336',
                'color:#fff',
                'padding:6px 12px',
                'border-radius:4px',
                'font-family:sans-serif',
                'z-index:99999',
            ].join(';');
            errEl.textContent = message;
            container.appendChild(errEl);
            currentElement = errEl;

            timeoutId = setTimeout(() => {
                if (errEl.parentNode) {
                    errEl.parentNode.removeChild(errEl);
                }
                currentElement = null;
                timeoutId = null;
            }, displayMs);
        },

        clear() {
            if (timeoutId) {
                clearTimeout(timeoutId);
                timeoutId = null;
            }
            if (currentElement?.parentNode) {
                currentElement.parentNode.removeChild(currentElement);
                currentElement = null;
            }
        }
    };
}
