/**
 * PK UI - UI state management utilities for PK files
 *
 * Provides helpers for managing loading states and retry logic.
 *
 * @example
 * ```typescript
 * // Show loading state while fetching
 * const result = await loading('#submit-btn', fetchData(), {
 *     text: 'Submitting...',
 *     disabled: true
 * });
 *
 * // Retry failed operations with exponential backoff
 * const data = await withRetry(() => fetch('/api/data'), {
 *     attempts: 3,
 *     backoff: 'exponential'
 * });
 * ```
 */

// ============================================================================
// Types
// ============================================================================

export interface LoadingOptions {
    /** CSS class to add during loading (default: 'loading') */
    className?: string;
    /** Text to show during loading (replaces innerText) */
    text?: string;
    /** Disable the element during loading (default: true) */
    disabled?: boolean;
    /** Minimum duration in ms to show loading state (prevents flicker) */
    minDuration?: number;
    /** Called when loading starts */
    onStart?: () => void;
    /** Called when loading ends (success or error) */
    onEnd?: () => void;
}

export interface RetryOptions {
    /** Number of retry attempts (default: 3) */
    attempts?: number;
    /** Backoff strategy: 'linear' or 'exponential' (default: 'exponential') */
    backoff?: 'linear' | 'exponential';
    /** Initial delay in ms (default: 1000) */
    delay?: number;
    /** Maximum delay in ms (default: 30000) */
    maxDelay?: number;
    /** Called before each retry attempt */
    onRetry?: (attempt: number, error: Error) => void;
    /** Condition to check if retry should happen (default: always retry) */
    shouldRetry?: (error: Error) => boolean;
}

export interface RetryResult<T> {
    /** The successful result */
    data: T;
    /** Number of attempts it took */
    attempts: number;
}

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Resolves a target to an HTMLElement
 */
function resolveElement(target: string | HTMLElement): HTMLElement | null {
    if (target instanceof HTMLElement) {
        return target;
    }

    // Try p-ref first
    const byRef = document.querySelector(`[p-ref="${target}"]`);
    if (byRef instanceof HTMLElement) {
        return byRef;
    }

    // Fall back to CSS selector
    const bySelector = document.querySelector(target);
    if (bySelector instanceof HTMLElement) {
        return bySelector;
    }

    return null;
}

/**
 * Calculates delay for retry attempt
 */
function calculateDelay(
    attempt: number,
    options: Required<Pick<RetryOptions, 'backoff' | 'delay' | 'maxDelay'>>
): number {
    let calculatedDelay: number;

    if (options.backoff === 'linear') {
        calculatedDelay = options.delay * attempt;
    } else {
        // Exponential: delay * 2^(attempt-1)
        calculatedDelay = options.delay * Math.pow(2, attempt - 1);
    }

    return Math.min(calculatedDelay, options.maxDelay);
}

/**
 * Sleep for a specified duration
 */
function sleep(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
}

// ============================================================================
// Exported Functions
// ============================================================================

/**
 * Wraps a promise with automatic loading state management
 *
 * Adds a loading class, optionally changes text, and disables the element
 * while the promise is pending.
 *
 * @param target - Element selector, p-ref name, or HTMLElement
 * @param promise - The promise to track
 * @param options - Loading state options
 * @returns The promise result
 *
 * @example
 * ```typescript
 * // Basic usage - adds 'loading' class during operation
 * const result = await loading('#save-btn', saveData());
 *
 * // With text replacement
 * const result = await loading('#submit', submitForm(), {
 *     text: 'Submitting...',
 *     disabled: true
 * });
 *
 * // With minimum duration to prevent flicker
 * const result = await loading('.fetch-btn', fetchList(), {
 *     minDuration: 300
 * });
 *
 * // With callbacks
 * const result = await loading('#action', performAction(), {
 *     onStart: () => console.log('Started'),
 *     onEnd: () => console.log('Finished')
 * });
 * ```
 */
export async function loading<T>(
    target: string | HTMLElement,
    promise: Promise<T>,
    options: LoadingOptions = {}
): Promise<T> {
    const {
        className = 'loading',
        text,
        disabled = true,
        minDuration = 0,
        onStart,
        onEnd
    } = options;

    const element = resolveElement(target);
    if (!element) {
        console.warn(`[pk] loading: target "${target}" not found`);
        return promise;
    }

    // Store original state
    const originalText = element.innerText;
    const originalDisabled = element instanceof HTMLButtonElement ||
        element instanceof HTMLInputElement ||
        element instanceof HTMLSelectElement ||
        element instanceof HTMLTextAreaElement
        ? (element as HTMLButtonElement).disabled
        : false;

    // Apply loading state
    element.classList.add(className);
    if (text !== undefined) {
        element.innerText = text;
    }
    if (disabled && 'disabled' in element) {
        (element as HTMLButtonElement).disabled = true;
    }

    onStart?.();

    const startTime = Date.now();

    try {
        const result = await promise;

        // Ensure minimum duration
        const elapsed = Date.now() - startTime;
        if (elapsed < minDuration) {
            await sleep(minDuration - elapsed);
        }

        return result;
    } finally {
        // Restore original state
        element.classList.remove(className);
        if (text !== undefined) {
            element.innerText = originalText;
        }
        if (disabled && 'disabled' in element) {
            (element as HTMLButtonElement).disabled = originalDisabled;
        }

        onEnd?.();
    }
}

/**
 * Wraps an async function with retry logic
 *
 * Automatically retries failed operations with configurable backoff.
 *
 * @param fn - Async function to retry
 * @param options - Retry configuration
 * @returns The successful result
 * @throws The last error if all attempts fail
 *
 * @example
 * ```typescript
 * // Basic retry with defaults (3 attempts, exponential backoff)
 * const data = await withRetry(() => fetch('/api/data').then(r => r.json()));
 *
 * // Custom retry configuration
 * const result = await withRetry(
 *     () => unreliableOperation(),
 *     {
 *         attempts: 5,
 *         backoff: 'linear',
 *         delay: 500,
 *         onRetry: (attempt, error) => {
 *             console.log(`Retry ${attempt}: ${error.message}`);
 *         }
 *     }
 * );
 *
 * // Conditional retry
 * const data = await withRetry(
 *     () => fetchWithTimeout(),
 *     {
 *         shouldRetry: (error) => error.name === 'TimeoutError'
 *     }
 * );
 * ```
 */
export async function withRetry<T>(
    fn: () => Promise<T>,
    options: RetryOptions = {}
): Promise<T> {
    const {
        attempts = 3,
        backoff = 'exponential',
        delay = 1000,
        maxDelay = 30000,
        onRetry,
        shouldRetry = () => true
    } = options;

    let lastError: Error | null = null;

    for (let attempt = 1; attempt <= attempts; attempt++) {
        try {
            return await fn();
        } catch (error) {
            lastError = error instanceof Error ? error : new Error(String(error));

            // Check if we should retry
            if (attempt === attempts || !shouldRetry(lastError)) {
                throw lastError;
            }

            // Notify about retry
            onRetry?.(attempt, lastError);

            // Wait before retrying
            const waitTime = calculateDelay(attempt, {backoff, delay, maxDelay});
            await sleep(waitTime);
        }
    }

    // This should never be reached, but TypeScript needs it
    throw lastError ?? new Error('Retry failed');
}

/**
 * Shows a loading indicator on an element while a function executes
 *
 * Similar to `loading` but accepts a function instead of a promise,
 * allowing for more complex operations.
 *
 * @param target - Element selector, p-ref name, or HTMLElement
 * @param fn - Async function to execute
 * @param options - Loading state options
 * @returns The function result
 *
 * @example
 * ```typescript
 * const result = await withLoading('#btn', async () => {
 *     const response = await fetch('/api/data');
 *     const data = await response.json();
 *     return processData(data);
 * }, { text: 'Processing...' });
 * ```
 */
export async function withLoading<T>(
    target: string | HTMLElement,
    fn: () => Promise<T>,
    options: LoadingOptions = {}
): Promise<T> {
    return loading(target, fn(), options);
}

/**
 * Creates a debounced version of a function
 *
 * The function will only execute after the specified delay has passed
 * without any new calls.
 *
 * @param fn - Function to debounce
 * @param delay - Delay in milliseconds
 * @returns Debounced function with cancel method
 *
 * @example
 * ```typescript
 * const debouncedSearch = debounceAsync(async (query: string) => {
 *     return await searchAPI(query);
 * }, 300);
 *
 * // Only the last call within 300ms will execute
 * debouncedSearch('h');
 * debouncedSearch('he');
 * debouncedSearch('hello'); // Only this executes
 *
 * // Cancel pending execution
 * debouncedSearch.cancel();
 * ```
 */
export function debounceAsync<T extends unknown[], R>(
    fn: (...args: T) => Promise<R>,
    delay: number
): ((...args: T) => Promise<R>) & { cancel: () => void } {
    let timeoutId: ReturnType<typeof setTimeout> | null = null;
    let pendingResolve: ((value: R) => void) | null = null;
    let pendingReject: ((error: Error) => void) | null = null;

    const debounced = (...args: T): Promise<R> => {
        // Cancel previous timeout
        if (timeoutId !== null) {
            clearTimeout(timeoutId);
        }

        return new Promise<R>((resolve, reject) => {
            pendingResolve = resolve;
            pendingReject = reject;

            timeoutId = setTimeout(() => {
                void (async () => {
                    timeoutId = null;
                    try {
                        const result = await fn(...args);
                        pendingResolve?.(result);
                    } catch (error) {
                        pendingReject?.(error instanceof Error ? error : new Error(String(error)));
                    }
                })();
            }, delay);
        });
    };

    debounced.cancel = (): void => {
        if (timeoutId !== null) {
            clearTimeout(timeoutId);
            timeoutId = null;
        }
    };

    return debounced;
}

/**
 * Creates a throttled version of an async function
 *
 * The function will execute immediately on the first call, then ignore
 * subsequent calls until the delay has passed.
 *
 * @param fn - Function to throttle
 * @param delay - Minimum delay between executions in milliseconds
 * @returns Throttled function
 *
 * @example
 * ```typescript
 * const throttledSave = throttleAsync(async (data: Data) => {
 *     await saveToServer(data);
 * }, 1000);
 *
 * // First call executes immediately
 * throttledSave(data1);
 *
 * // These are ignored (within 1000ms)
 * throttledSave(data2);
 * throttledSave(data3);
 *
 * // After 1000ms, next call will execute
 * ```
 */
export function throttleAsync<T extends unknown[], R>(
    fn: (...args: T) => Promise<R>,
    delay: number
): (...args: T) => Promise<R | undefined> {
    let lastCall = 0;
    let pendingPromise: Promise<R> | null = null;

    return async (...args: T): Promise<R | undefined> => {
        const now = Date.now();

        if (now - lastCall >= delay) {
            lastCall = now;
            pendingPromise = fn(...args);
            return pendingPromise;
        }

        // Return the pending promise if one exists
        if (pendingPromise) {
            return pendingPromise;
        }

        return undefined;
    };
}
