/**
 * PK Advanced - Advanced utilities for PK files
 *
 * Provides helpers for visibility detection, cancellable operations,
 * and other advanced patterns.
 *
 * @example
 * ```typescript
 * // Lazy load when visible
 * const stop = whenVisible('#lazy-section', () => {
 *     loadHeavyContent();
 * });
 *
 * // Cancellable fetch
 * const { promise, abort } = withAbortSignal((signal) =>
 *     fetch('/api/data', { signal })
 * );
 *
 * // Cancel if needed
 * abort();
 * ```
 */

// ============================================================================
// Types
// ============================================================================

export interface WhenVisibleOptions {
    /** IntersectionObserver threshold (0-1, default: 0) */
    threshold?: number | number[];
    /** Root element for intersection (default: viewport) */
    root?: Element | null;
    /** Root margin (default: '0px') */
    rootMargin?: string;
    /** Only trigger once, then disconnect (default: true) */
    once?: boolean;
}

export interface AbortableOperation<T> {
    /** The promise for the operation */
    promise: Promise<T>;
    /** Abort the operation */
    abort: () => void;
    /** The AbortSignal being used */
    signal: AbortSignal;
}

export interface PollingOptions {
    /** Polling interval in milliseconds */
    interval: number;
    /** Stop polling when this returns true */
    until?: () => boolean | Promise<boolean>;
    /** Maximum number of polls (default: unlimited) */
    maxAttempts?: number;
    /** Called on each poll with the result */
    onPoll?: (result: unknown, attempt: number) => void;
    /** Called when polling stops */
    onStop?: (reason: 'condition' | 'maxAttempts' | 'manual') => void;
}

export interface MutationWatchOptions {
    /** Watch for child additions/removals (default: true) */
    childList?: boolean;
    /** Watch attribute changes (default: false) */
    attributes?: boolean;
    /** Watch text content changes (default: false) */
    characterData?: boolean;
    /** Watch all descendants, not just direct children (default: false) */
    subtree?: boolean;
    /** Only watch specific attributes */
    attributeFilter?: string[];
}

// ============================================================================
// Constants
// ============================================================================

/** Default timeout in ms for requestIdleCallback fallback (when not supported) */
const DEFAULT_IDLE_CALLBACK_TIMEOUT_MS = 50;

// ============================================================================
// Helper Functions
// ============================================================================

/**
 * Resolves a target to an Element
 */
function resolveElement(target: string | Element): Element | null {
    if (target instanceof Element) {
        return target;
    }

    // Try p-ref first
    const byRef = document.querySelector(`[p-ref="${target}"]`);
    if (byRef) {
        return byRef;
    }

    // Fall back to CSS selector
    return document.querySelector(target);
}

// ============================================================================
// Exported Functions
// ============================================================================

/**
 * Executes a callback when an element becomes visible in the viewport
 *
 * Uses IntersectionObserver for efficient visibility detection.
 *
 * @param target - Element selector, p-ref name, or Element
 * @param callback - Function to call when visible
 * @param options - IntersectionObserver options
 * @returns Function to stop watching
 *
 * @example
 * ```typescript
 * // Basic usage - trigger once when visible
 * const stop = whenVisible('#lazy-image', (entry) => {
 *     loadImage(entry.target);
 * });
 *
 * // Trigger every time element enters/exits viewport
 * const stop = whenVisible('#video-player', (entry) => {
 *     if (entry.isIntersecting) {
 *         videoPlayer.play();
 *     } else {
 *         videoPlayer.pause();
 *     }
 * }, { once: false });
 *
 * // With threshold (50% visible)
 * const stop = whenVisible('#hero', () => {
 *     animateHero();
 * }, { threshold: 0.5 });
 *
 * // Stop watching
 * onCleanup(stop);
 * ```
 */
export function whenVisible(
    target: string | Element,
    callback: (entry: IntersectionObserverEntry) => void,
    options: WhenVisibleOptions = {}
): () => void {
    const {
        threshold = 0,
        root = null,
        rootMargin = '0px',
        once: triggerOnce = true
    } = options;

    const element = resolveElement(target);
    if (!element) {
        console.warn(`[pk] whenVisible: target "${target}" not found`);
        return () => {
            // No-op
        };
    }

    const observer = new IntersectionObserver(
        (entries) => {
            for (const entry of entries) {
                if (entry.isIntersecting) {
                    callback(entry);
                    if (triggerOnce) {
                        observer.disconnect();
                    }
                } else if (!triggerOnce) {
                    // For continuous watching, also notify when leaving viewport
                    callback(entry);
                }
            }
        },
        {threshold, root, rootMargin}
    );

    observer.observe(element);

    return () => {
        observer.disconnect();
    };
}

/**
 * Creates a cancellable async operation using AbortController
 *
 * @param fn - Async function that receives an AbortSignal
 * @returns Object with promise, abort function, and signal
 *
 * @example
 * ```typescript
 * // Cancellable fetch
 * const { promise, abort } = withAbortSignal((signal) =>
 *     fetch('/api/large-data', { signal }).then(r => r.json())
 * );
 *
 * // Cancel if user navigates away
 * onCleanup(abort);
 *
 * // Or cancel manually
 * setTimeout(abort, 5000); // Cancel after 5 seconds
 *
 * try {
 *     const data = await promise;
 * } catch (e) {
 *     if (e.name === 'AbortError') {
 *         console.log('Request was cancelled');
 *     }
 * }
 * ```
 */
export function withAbortSignal<T>(
    fn: (signal: AbortSignal) => Promise<T>
): AbortableOperation<T> {
    const controller = new AbortController();

    return {
        promise: fn(controller.signal),
        abort: () => controller.abort(),
        signal: controller.signal
    };
}

/**
 * Creates a timeout that returns a promise
 *
 * @param ms - Timeout duration in milliseconds
 * @returns Object with promise and cancel function
 *
 * @example
 * ```typescript
 * // Wait for 2 seconds
 * await timeout(2000).promise;
 *
 * // Cancellable timeout
 * const { promise, cancel } = timeout(5000);
 * setTimeout(cancel, 1000); // Cancel after 1 second
 *
 * try {
 *     await promise;
 *     console.log('5 seconds passed');
 * } catch (e) {
 *     console.log('Timeout was cancelled');
 * }
 * ```
 */
export function timeout(ms: number): { promise: Promise<void>; cancel: () => void } {
    let timeoutId: ReturnType<typeof setTimeout> | null = null;
    let rejectFn: ((reason: Error) => void) | null = null;

    const promise = new Promise<void>((resolve, reject) => {
        rejectFn = reject;
        timeoutId = setTimeout(resolve, ms);
    });

    return {
        promise,
        cancel: () => {
            if (timeoutId !== null) {
                clearTimeout(timeoutId);
                timeoutId = null;
                rejectFn?.(new Error('Timeout cancelled'));
            }
        }
    };
}

/**
 * Polls a function at regular intervals until a condition is met
 *
 * @param fn - Function to poll
 * @param options - Polling configuration
 * @returns Function to stop polling
 *
 * @example
 * ```typescript
 * // Poll until condition is true
 * const stop = poll(
 *     () => fetch('/api/job/123').then(r => r.json()),
 *     {
 *         interval: 2000,
 *         until: (result) => result.status === 'complete',
 *         onPoll: (result, attempt) => {
 *             console.log(`Poll ${attempt}: ${result.status}`);
 *         },
 *         onStop: (reason) => {
 *             console.log(`Stopped: ${reason}`);
 *         }
 *     }
 * );
 *
 * // Stop manually
 * setTimeout(stop, 30000);
 * ```
 */
export function poll<T>(
    fn: () => T | Promise<T>,
    options: PollingOptions
): () => void {
    const {
        interval,
        until,
        maxAttempts,
        onPoll,
        onStop
    } = options;

    let stopped = false;
    let attempt = 0;
    let timeoutId: ReturnType<typeof setTimeout> | null = null;

    const runPoll = async (): Promise<void> => {
        if (stopped) {
            return;
        }

        attempt++;

        try {
            const result = await fn();
            onPoll?.(result, attempt);

            // Check stop condition
            if (until) {
                const shouldStop = await until();
                if (shouldStop) {
                    stopped = true;
                    onStop?.('condition');
                    return;
                }
            }

            // Check max attempts
            if (maxAttempts !== undefined && attempt >= maxAttempts) {
                stopped = true;
                onStop?.('maxAttempts');
                return;
            }

            // Schedule next poll
            timeoutId = setTimeout(() => {
                void runPoll();
            }, interval);
        } catch (error) {
            console.error('[pk] poll error:', {
                fn: fn.name || 'anonymous',
                interval,
                stopped,
                error
            });
            // Continue polling on error unless stopped
            if (!stopped) {
                timeoutId = setTimeout(() => {
                    void runPoll();
                }, interval);
            }
        }
    };

    // Start polling
    void runPoll();

    // Return stop function
    return () => {
        stopped = true;
        if (timeoutId !== null) {
            clearTimeout(timeoutId);
            timeoutId = null;
        }
        onStop?.('manual');
    };
}

/**
 * Watches for DOM mutations on an element
 *
 * @param target - Element selector, p-ref name, or Element
 * @param callback - Function to call on mutations
 * @param options - MutationObserver options
 * @returns Function to stop watching
 *
 * @example
 * ```typescript
 * // Watch for child changes
 * const stop = watchMutations('#container', (mutations) => {
 *     for (const mutation of mutations) {
 *         if (mutation.addedNodes.length > 0) {
 *             console.log('Children added');
 *         }
 *     }
 * });
 *
 * // Watch for attribute changes
 * const stop = watchMutations('#button', (mutations) => {
 *     console.log('Button attributes changed');
 * }, { attributes: true, childList: false });
 *
 * // Cleanup
 * onCleanup(stop);
 * ```
 */
export function watchMutations(
    target: string | Element,
    callback: (mutations: MutationRecord[]) => void,
    options: MutationWatchOptions = {}
): () => void {
    const {
        childList = true,
        attributes = false,
        characterData = false,
        subtree = false,
        attributeFilter
    } = options;

    const element = resolveElement(target);
    if (!element) {
        console.warn(`[pk] watchMutations: target "${target}" not found`);
        return () => {
            // No-op
        };
    }

    const observer = new MutationObserver(callback);

    observer.observe(element, {
        childList,
        attributes,
        characterData,
        subtree,
        attributeFilter
    });

    return () => {
        observer.disconnect();
    };
}

/**
 * Runs a function when the document is idle
 *
 * Uses requestIdleCallback when available, falls back to setTimeout.
 *
 * @param fn - Function to run during idle time
 * @param options - RequestIdleCallback options
 * @returns Function to cancel
 *
 * @example
 * ```typescript
 * // Run non-critical work during idle time
 * const cancel = whenIdle(() => {
 *     analytics.sendEvents();
 * });
 *
 * // With timeout (run after 2s max)
 * const cancel = whenIdle(() => {
 *     prefetchImages();
 * }, { timeout: 2000 });
 * ```
 */
export function whenIdle(
    fn: (deadline?: IdleDeadline) => void,
    options?: IdleRequestOptions
): () => void {
    if ('requestIdleCallback' in window) {
        const id = window.requestIdleCallback(fn, options);
        return () => window.cancelIdleCallback(id);
    }

    // Fallback for browsers without requestIdleCallback
    const timeoutMs = options?.timeout ?? DEFAULT_IDLE_CALLBACK_TIMEOUT_MS;
    const id = setTimeout(() => fn(), timeoutMs);
    return () => clearTimeout(id);
}

/**
 * Creates a promise that resolves on the next animation frame
 *
 * @returns Promise that resolves with the timestamp
 *
 * @example
 * ```typescript
 * // Wait for next frame before measuring
 * await nextFrame();
 * const rect = element.getBoundingClientRect();
 *
 * // Chain multiple frame waits
 * await nextFrame();
 * element.classList.add('animate');
 * await nextFrame();
 * element.classList.add('visible');
 * ```
 */
export function nextFrame(): Promise<number> {
    return new Promise(resolve => {
        requestAnimationFrame(resolve);
    });
}

/**
 * Waits for multiple animation frames
 *
 * @param count - Number of frames to wait
 * @returns Promise that resolves after the frames
 *
 * @example
 * ```typescript
 * // Wait for 2 frames (useful for ensuring reflow)
 * element.style.opacity = '0';
 * await waitFrames(2);
 * element.style.opacity = '1';
 * element.style.transition = 'opacity 0.3s';
 * ```
 */
export async function waitFrames(count: number): Promise<void> {
    for (let i = 0; i < count; i++) {
        await nextFrame();
    }
}

/**
 * Creates a deferred promise that can be resolved/rejected externally
 *
 * @returns Object with promise, resolve, and reject
 *
 * @example
 * ```typescript
 * const { promise, resolve, reject } = deferred<string>();
 *
 * // Pass promise to something that will await it
 * someAsyncConsumer(promise);
 *
 * // Resolve it later
 * setTimeout(() => resolve('done'), 1000);
 * ```
 */
export function deferred<T>(): {
    promise: Promise<T>;
    resolve: (value: T) => void;
    reject: (reason?: unknown) => void;
} {
    let resolve!: (value: T) => void;
    let reject!: (reason?: unknown) => void;

    const promise = new Promise<T>((res, rej) => {
        resolve = res;
        reject = rej;
    });

    return {promise, resolve, reject};
}

/**
 * Executes a function only once, caching the result
 *
 * @param fn - Function to execute once
 * @returns Wrapped function that returns cached result
 *
 * @example
 * ```typescript
 * const getConfig = once(async () => {
 *     console.log('Fetching config...');
 *     return await fetch('/api/config').then(r => r.json());
 * });
 *
 * // First call fetches
 * const config1 = await getConfig(); // Logs "Fetching config..."
 *
 * // Subsequent calls return cached result
 * const config2 = await getConfig(); // No log, returns cached
 * ```
 */
export function once<T>(fn: () => T): () => T {
    let called = false;
    let result: T;

    return () => {
        if (!called) {
            called = true;
            result = fn();
        }
        return result;
    };
}
