/**
 * Virtual DOM Factory - Functions for creating virtual nodes
 */

import type {DomAPI, VirtualNode} from "./types";

/**
 * DOM API object for creating virtual nodes.
 * Used by compiled components to build their VDOM tree.
 */
export const dom: DomAPI = {
    ws(id) {
        return dom.txt(" ", id, {_isWhitespace: true});
    },

    txt(content, id, props = null) {
        const finalProps = {...(props ?? {})};
        return {
            _type: "text",
            text: String(content ?? ""),
            props: finalProps,
            children: null,
            key: id,
        };
    },

    html(content, id) {
        return {
            _type: "element",
            tag: "div",
            props: {},
            children: null,
            html: content,
            key: id,
        };
    },

    cmt(content, id, props = null) {
        const finalProps = {...(props ?? {})};
        return {
            _type: "comment",
            text: String(content ?? ""),
            props: finalProps,
            children: null,
            key: id,
        };
    },

    el(tag, id, props = {}, children = []) {
        const finalProps = {...props};
        const childArray = normalizeChildren(children);
        return {
            _type: "element",
            tag,
            props: finalProps,
            children: childArray as VirtualNode[],
            key: id,
        };
    },

    frag(id, children = [], props = {}) {
        const finalProps = {...props};
        const childArray = normalizeChildren(children);
        return {
            _type: "fragment",
            props: finalProps,
            children: childArray as VirtualNode[],
            key: id,
        };
    },
};

function normalizeChildren(children: VirtualNode | VirtualNode[] | null | undefined): VirtualNode[] {
    if (children == null) {
        return [];
    }
    if (Array.isArray(children)) {
        // Flatten nested arrays (from p-for with siblings) and filter nullish values
        return children.flat(Infinity).filter(isDef) as VirtualNode[];
    }
    return [children].filter(isDef);
}

function isDef<T>(x: T | undefined | null): x is T {
    return x != null;
}
