/**
 * ActionClient - Executes server actions via HTTP
 */

import type {HelperRegistry} from '@/services/HelperRegistry';
import type {ErrorDisplay} from '@/services/ErrorDisplay';
import type {ActionArg} from '@/services/DOMBinder';
import {HookEvent, type HookManager} from '@/services/HookManager';
import type {FormStateManager} from '@/services/FormStateManager';
import {
    type DOMOperations,
    type WindowOperations,
    type HTTPOperations,
    browserDOMOperations,
    browserWindowOperations,
    browserHTTPOperations
} from '@/core/BrowserAPIs';
import {getCSRFTokenFromMeta, getCSRFEphemeralFromMeta} from '@/core/CSRFUtils';

export interface ActionResponse {
    status: number;
    message?: string;
    /** Structured error code (e.g., 'csrf_expired', 'csrf_invalid') */
    error?: string;
    errors?: Record<string, string>;
    helpers?: { name: string; args?: unknown[] }[];
}

/** CSRF error codes returned by the server */
const CSRF_ERROR_EXPIRED = 'csrf_expired';
const CSRF_ERROR_INVALID = 'csrf_invalid';

/** HTTP status codes */
const HTTP_STATUS_FORBIDDEN = 403;

export interface ActionClientDependencies {
    helperRegistry: HelperRegistry;
    errorDisplay: ErrorDisplay;
    /** DOM operations - defaults to browser document */
    domOps?: DOMOperations;
    /** Window operations - defaults to browser window */
    windowOps?: WindowOperations;
    /** HTTP operations - defaults to browser fetch */
    http?: HTTPOperations;
    /** Hook manager for analytics events (optional) */
    hookManager?: HookManager;
    /** Form state manager for marking forms clean after successful submission (optional) */
    formStateManager?: FormStateManager;
}

export interface ActionClient {
    /** Execute a server action */
    runAction(
        actionName: string,
        element: HTMLElement,
        evt?: Event,
        httpMethod?: string,
        actionArgs?: ActionArg[]
    ): void;

    /**
     * Call a server action programmatically and return the response.
     * Unlike runAction, this returns a Promise with the response and does NOT
     * automatically execute helpers - the caller is responsible for processing them.
     *
     * @param actionName - The name of the action to call
     * @param payload - Optional JSON payload to send with the request
     * @returns Promise resolving to the ActionResponse
     */
    callAction(
        actionName: string,
        payload?: Record<string, unknown>
    ): Promise<ActionResponse>;

    /** Execute a helper from server response */
    executeServerHelper(name: string, args: unknown[], triggerElement: HTMLElement, event?: Event): void;
}

/**
 * Checks if the response indicates a CSRF error that requires recovery.
 */
function isCSRFError(status: number, responseData: ActionResponse): boolean {
    return status === HTTP_STATUS_FORBIDDEN &&
        (responseData.error === CSRF_ERROR_EXPIRED || responseData.error === CSRF_ERROR_INVALID);
}

/**
 * Attempts to recover from a CSRF error by refreshing the partial and retrying.
 * Returns true if recovery was attempted, false if caller should continue processing.
 */
function attemptCSRFRecovery(
    responseData: ActionResponse,
    element: HTMLElement,
    windowOps: WindowOperations,
    errorDisplay: ErrorDisplay,
    retryAction: () => void
): boolean {
    // For csrf_invalid (corrupted token), just reload
    if (responseData.error === CSRF_ERROR_INVALID) {
        windowOps.locationReload();
        return true;
    }

    // For csrf_expired, try to refresh the partial and retry
    const partial = element.closest('[partial_src]') as HTMLElement | null;
    if (partial) {
        partial.dispatchEvent(new CustomEvent('refresh-partial', {
            bubbles: false,
            detail: {
                afterMorph: () => {
                    // Find the refreshed element with fresh CSRF tokens
                    const refreshedEl = partial.querySelector('[data-csrf-action-token]') as HTMLElement | null;
                    if (refreshedEl) {
                        retryAction();
                    } else {
                        console.warn('ActionClient: Could not find element with CSRF token after partial refresh');
                        errorDisplay.show('Session expired. Please try again.');
                    }
                }
            }
        }));
        return true;
    }

    // No partial found, fallback to page reload
    windowOps.locationReload();
    return true;
}

/**
 * Creates an ActionClient instance
 */
// eslint-disable-next-line max-lines-per-function
export function createActionClient(deps: ActionClientDependencies): ActionClient {
    const {helperRegistry, errorDisplay, hookManager, formStateManager} = deps;
    const domOps = deps.domOps ?? browserDOMOperations;
    const windowOps = deps.windowOps ?? browserWindowOperations;
    const http = deps.http ?? browserHTTPOperations;

    const clearPreviousErrors = (form: HTMLElement) => {
        form.querySelectorAll<HTMLElement>('[error]').forEach(el => {
            el.removeAttribute('error');
            const errorSlot = el.shadowRoot?.querySelector('slot[name="error"]');
            if (errorSlot) {
                (errorSlot as HTMLSlotElement).assignedElements().forEach(e => e.remove());
            }
        });
    };

    const applyServerErrors = (form: HTMLElement, errors: Record<string, string>) => {
        clearPreviousErrors(form);

        for (const [fieldName, errorMessage] of Object.entries(errors)) {
            const fields = form.querySelectorAll<HTMLElement>(`[name="${fieldName}"]`);

            if (fields.length > 0) {
                fields.forEach(field => {
                    field.setAttribute('error', errorMessage);

                    if (field.shadowRoot) {
                        const errorElement = domOps.createElement('span');
                        errorElement.slot = 'error';
                        errorElement.textContent = errorMessage;
                        errorElement.style.color = 'var(--g-color-error, #F04438)';
                        errorElement.style.fontSize = '0.875rem';
                        errorElement.style.marginTop = '4px';

                        field.appendChild(errorElement);
                    }
                });
            } else {
                console.warn(`ActionClient: Could not find a form field with name "${fieldName}" to apply validation error.`);
            }
        }
    };

    const handleActionResponse = (
        responseOk: boolean,
        statusCode: number,
        actionName: string,
        responseData: ActionResponse,
        formElement: HTMLFormElement | null,
        element: HTMLElement,
        evt?: Event
    ) => {
        console.warn('[ActionClient] handleActionResponse called:', {
            actionName,
            responseOk,
            statusCode,
            helpersCount: responseData.helpers?.length ?? 0,
            responseData
        });

        if (!responseOk) {
            console.warn(`Action ${actionName} failed with status ${statusCode}`);

            if (responseData.errors) {
                console.error('Validation errors:', responseData.errors);
                const targetElement = formElement ?? element;
                if (targetElement.tagName === 'FORM') {
                    applyServerErrors(targetElement, responseData.errors);
                }
            }
        }

        // Mark form as clean after successful submission to prevent
        // "unsaved changes" warnings when navigating away
        if (responseOk && formElement && formStateManager) {
            formStateManager.markFormClean(formElement);
        }

        if (responseData.helpers && Array.isArray(responseData.helpers)) {
            console.warn('[ActionClient] Executing helpers:', responseData.helpers);
            for (const helper of responseData.helpers) {
                try {
                    console.warn('[ActionClient] Executing helper:', helper.name, helper.args);
                    executeServerHelper(helper.name, helper.args ?? [], element, evt);
                    console.warn('[ActionClient] Helper executed successfully:', helper.name);
                } catch (err) {
                    // This catch is a safety net in case executeServerHelper itself throws
                    console.error(`ActionClient: Failed to execute helper "${helper.name}":`, err);
                }
            }
        } else {
            console.warn('[ActionClient] No helpers to execute');
        }
    };

    // eslint-disable-next-line max-lines-per-function, complexity, sonarjs/cognitive-complexity
    function runAction(
        actionName: string,
        element: HTMLElement,
        evt?: Event,
        httpMethod: string = 'POST',
        actionArgs: ActionArg[] = []
    ): void {
        console.warn('[ActionClient] runAction called:', { actionName, element, httpMethod });

        if (element.tagName === 'FORM' || (element as HTMLButtonElement).type === 'submit') {
            evt?.preventDefault();
        }

        const actionStartTime = Date.now();

        // Emit action start hook
        hookManager?.emit(HookEvent.ACTION_START, {
            action: actionName,
            method: httpMethod,
            elementTag: element.tagName.toLowerCase(),
            timestamp: actionStartTime
        });

        let body: BodyInit | undefined;
        const bodyJSON: Record<string, unknown> = {};
        const headers: Record<string, string> = {};

        const formId = element.getAttribute('p-action:form');
        const formElement = formId
            ? (domOps.getElementById(formId) as HTMLFormElement)
            : element.closest('form');

        console.warn('[ActionClient] Form lookup:', {
            formId,
            formElement: formElement?.tagName,
            elementTag: element.tagName,
            hasClosestForm: !!element.closest('form')
        });

        if (formElement) {
            console.warn('[ActionClient] Found form element:', {
                tagName: formElement.tagName,
                id: formElement.id,
                formElementCount: formElement.elements?.length
            });

            if (formElement.tagName === 'FORM') {
                clearPreviousErrors(formElement);

                // Validate form before submission using native HTML5 validation
                // This ensures required fields, pattern validation, and custom validity
                // (including form-associated custom elements like pp-select) are checked
                const isValid = formElement.reportValidity();
                console.warn('[ActionClient] Form validation result:', {
                    isValid,
                    formId: formElement.id,
                    checkValidity: formElement.checkValidity()
                });

                if (!isValid) {
                    console.warn('[ActionClient] Form validation FAILED - aborting submission');
                    // Emit action complete hook with validation failure
                    hookManager?.emit(HookEvent.ACTION_COMPLETE, {
                        action: actionName,
                        method: httpMethod,
                        elementTag: element.tagName.toLowerCase(),
                        success: false,
                        statusCode: 0,
                        duration: Date.now() - actionStartTime,
                        timestamp: Date.now(),
                        validationFailed: true
                    });
                    return;
                }
                console.warn('[ActionClient] Form validation PASSED - proceeding with submission');
            }
            body = new FormData(formElement);
        } else {
            console.warn('[ActionClient] No form element found, using JSON body');
            headers['Content-Type'] = 'application/json';
        }

        // Read CSRF tokens: element attributes take precedence, fallback to meta tags
        const ephemeralToken = element.getAttribute('data-csrf-ephemeral-token')
            ?? getCSRFEphemeralFromMeta()
            ?? '';
        const actionToken = element.getAttribute('data-csrf-action-token')
            ?? getCSRFTokenFromMeta()
            ?? '';
        if (actionToken) {
            headers['X-CSRF-Action-Token'] = actionToken;
        }

        let actionUrl = `/_pp/actions/${actionName}?_f=1`;

        if (httpMethod === 'GET') {
            const urlObj = new URL(actionUrl, windowOps.getLocationOrigin());

            if (ephemeralToken) {
                urlObj.searchParams.set('_csrf_ephemeral_token', ephemeralToken);
            }

            if (actionArgs.length > 0) {
                urlObj.searchParams.set('args', encodeURIComponent(actionArgs.map((a: ActionArg) => a.v).join(',')));
            }

            actionUrl = urlObj.toString();
            body = undefined;
        } else if (body && (body instanceof FormData || body instanceof URLSearchParams)) {
            // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition
            if (body && ephemeralToken) {
                body.append('_csrf_ephemeral_token', ephemeralToken);
            }
        } else if (headers['Content-Type'] === 'application/json') {
            if (actionArgs.length > 0) {
                bodyJSON['args'] = actionArgs
                    .map((a: ActionArg, i: number) => ({[i]: a.v}))
                    .reduce((acc, b) => ({...acc, ...b}), {});
            }
            if (ephemeralToken) {
                bodyJSON['_csrf_ephemeral_token'] = ephemeralToken;
            }

            // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- bodyJSON always exists
            body = JSON.stringify(bodyJSON ?? {});
        }

        http.fetch(actionUrl, {
            method: httpMethod,
            headers,
            body,
            credentials: 'same-origin'
        })
            .then(async response => {
                let responseData: ActionResponse | null = null;

                try {
                    responseData = (await response.json()) as ActionResponse;
                } catch (e) {
                    console.error('ActionClient: Failed to parse JSON response body:', e);
                    throw new Error('Failed to parse server response');
                }

                // Emit action complete hook
                hookManager?.emit(HookEvent.ACTION_COMPLETE, {
                    action: actionName,
                    method: httpMethod,
                    elementTag: element.tagName.toLowerCase(),
                    success: response.ok,
                    statusCode: response.status,
                    duration: Date.now() - actionStartTime,
                    timestamp: Date.now()
                });

                // Handle CSRF errors with recovery
                if (isCSRFError(response.status, responseData)) {
                    console.warn(`ActionClient: CSRF error (${responseData.error}), attempting recovery`);
                    attemptCSRFRecovery(
                        responseData,
                        element,
                        windowOps,
                        errorDisplay,
                        () => runAction(actionName, element, evt, httpMethod, actionArgs)
                    );
                    return;
                }

                handleActionResponse(
                    response.ok,
                    response.status,
                    actionName,
                    responseData,
                    formElement,
                    element,
                    evt
                );
            })
            .catch(err => {
                // Emit action complete hook with failure
                hookManager?.emit(HookEvent.ACTION_COMPLETE, {
                    action: actionName,
                    method: httpMethod,
                    elementTag: element.tagName.toLowerCase(),
                    success: false,
                    statusCode: 0,
                    duration: Date.now() - actionStartTime,
                    timestamp: Date.now()
                });

                console.error('ActionClient: runAction error:', err);
                errorDisplay.show(`Action ${actionName} error: ${err}`);
            });
    }

    function executeServerHelper(
        name: string,
        args: unknown[],
        triggerElement: HTMLElement,
        event?: Event
    ): void {
        console.warn('[ActionClient] executeServerHelper:', { name, args, triggerElement });
        const helper = helperRegistry.get(name);
        if (helper) {
            try {
                const stringArgs = args.map(a => String(a));
                console.warn('[ActionClient] Calling helper function:', name, stringArgs);
                helper(triggerElement, event as Event, ...stringArgs);
                console.warn('[ActionClient] Helper function completed:', name);
            } catch (err) {
                console.error(`ActionClient: Helper "${name}" threw an error:`, err);
                console.error(`  Helper args:`, args);
                console.error(`  Trigger element:`, triggerElement);
            }
        } else {
            console.warn(`ActionClient: Unknown helper action: "${name}"`);
        }
    }

    /**
     * Call a server action programmatically and return the response.
     * Unlike runAction, this method:
     * - Returns a Promise with the ActionResponse
     * - Does NOT automatically execute helpers (caller handles them)
     * - Does NOT require an element reference
     * - Uses JSON payload instead of FormData
     */
    async function callAction(
        actionName: string,
        payload: Record<string, unknown> = {}
    ): Promise<ActionResponse> {
        const actionStartTime = Date.now();

        // Emit action start hook
        hookManager?.emit(HookEvent.ACTION_START, {
            action: actionName,
            method: 'POST',
            elementTag: 'programmatic',
            timestamp: actionStartTime
        });

        // Read CSRF tokens from meta tags
        const ephemeralToken = getCSRFEphemeralFromMeta() ?? '';
        const actionToken = getCSRFTokenFromMeta() ?? '';

        const headers: Record<string, string> = {
            'Content-Type': 'application/json'
        };

        if (actionToken) {
            headers['X-CSRF-Action-Token'] = actionToken;
        }

        // Build request body with CSRF token
        const bodyJSON: Record<string, unknown> = {
            ...payload
        };
        if (ephemeralToken) {
            bodyJSON['_csrf_ephemeral_token'] = ephemeralToken;
        }

        const actionUrl = `/_pp/actions/${actionName}?_f=1`;

        try {
            const response = await http.fetch(actionUrl, {
                method: 'POST',
                headers,
                body: JSON.stringify(bodyJSON),
                credentials: 'same-origin'
            });

            let responseData: ActionResponse;
            try {
                responseData = (await response.json()) as ActionResponse;
            } catch {
                throw new Error('Failed to parse server response');
            }

            // Emit action complete hook
            hookManager?.emit(HookEvent.ACTION_COMPLETE, {
                action: actionName,
                method: 'POST',
                elementTag: 'programmatic',
                success: response.ok,
                statusCode: response.status,
                duration: Date.now() - actionStartTime,
                timestamp: Date.now()
            });

            // Handle CSRF errors - for programmatic calls, we just throw
            if (isCSRFError(response.status, responseData)) {
                throw new Error(`CSRF error: ${responseData.error}. Please refresh the page.`);
            }

            return responseData;
        } catch (err) {
            // Emit action complete hook with failure
            hookManager?.emit(HookEvent.ACTION_COMPLETE, {
                action: actionName,
                method: 'POST',
                elementTag: 'programmatic',
                success: false,
                statusCode: 0,
                duration: Date.now() - actionStartTime,
                timestamp: Date.now()
            });

            throw err;
        }
    }

    return {
        runAction,
        callAction,
        executeServerHelper
    };
}
