/**
 * PPFramework - Main framework facade
 *
 * This is a thin facade that wires together all the framework services.
 * Individual services can be imported directly for more granular control.
 */

import {_runPageCleanup, _executeConnectedForPartials} from '@/pk';
import {getGlobalPageContext} from '@/services/PageContext';

// Services
import {
    type ActionArg,
    createDOMBinder,
    createErrorDisplay,
    createEventBus,
    createHelperRegistry,
    createLinkHeaderParser,
    createLoaderUI,
    createModuleLoader,
    createSpriteSheetManager,
    createSyncPartialManager,
    type EventBus,
    initModuleLoaderFromPage,
    type OpenModalOptions,
    type PPHelper
} from '@/services';

// New services for browser features
import {createHookManager, HookEvent, type HooksAPI} from '@/services/HookManager';
import {createNetworkStatus, type NetworkStatus} from '@/services/NetworkStatus';
import {createA11yAnnouncer, type A11yAnnouncer} from '@/services/A11yAnnouncer';
import {createFormStateManager, type FormStateManager} from '@/services/FormStateManager';

// Core (import from specific modules to avoid circular dependency with barrel export)
import {createFetchClient, type FetchResult} from '@/core/FetchClient';
import {createRouter, type NavigateOptions, type PageLoadScrollOptions} from '@/core/Router';
import {createActionClient} from '@/core/ActionClient';
import {createRemoteRenderer, type PatchTarget, type RemoteRenderOptions} from '@/core/RemoteRenderer';
import {createModalManager, type ModalRequestOptions} from '@/core/ModalManager';
import {addFragmentQuery, buildRemoteUrl, isSameDomain} from '@/core/URLUtils';

// Re-export types for backwards compatibility
export type {PPHelper} from '@/services';
export type {NavigateOptions, RemoteRenderOptions, PatchTarget, FetchResult};

/**
 * Scans DOM for partial elements and registers their name-to-ID mappings
 * in PageContext. This enables scoped function resolution and cross-partial
 * calls via @partial-name.fn() syntax.
 */
function registerPartialInstancesFromDOM(doc: Document | DocumentFragment): void {
    const partials = doc.querySelectorAll('[partial][data-partial-name]');
    const pageContext = getGlobalPageContext();

    for (const el of partials) {
        const partialId = el.getAttribute('partial');
        const partialName = el.getAttribute('data-partial-name');
        if (partialId && partialName) {
            pageContext.registerPartialInstance(partialName, partialId);
        }
    }
}

export interface PPFrameworkOptions {
    loaderColor?: string;
    beforeNavigate?: (targetUrl: string) => void;
    afterNavigate?: (targetUrl: string) => void;
}

// ============================================================================
// Global Helper Registry (for RegisterHelper compatibility)
// ============================================================================

const globalHelperRegistry = createHelperRegistry();

/**
 * Register a helper function for use in templates
 */
export function RegisterHelper(name: string, setupFunction: PPHelper): void {
    globalHelperRegistry.register(name, setupFunction);
}

// ============================================================================
// PPFramework Factory
// ============================================================================

interface PPFrameworkInstance {
    // State (exposed for backwards compatibility in tests)
    loadedModuleScripts: Set<string>;
    navigating: boolean;
    loaderElement: HTMLDivElement | null;
    currentAbortController: AbortController | null;
    globalConfig: PPFrameworkOptions;

    // Core methods
    init(options?: PPFrameworkOptions): void;

    navigateTo(targetUrl: string, evt?: Event, options?: NavigateOptions): Promise<void>;

    remoteRender(options: RemoteRenderOptions): Promise<void>;

    runServerAction(
        actionName: string,
        element: HTMLElement,
        evt?: Event,
        httpMethod?: string,
        actionArgs?: ActionArg[]
    ): void;

    /**
     * Call a server action programmatically and return the response.
     * Unlike runServerAction, this returns a Promise with the response and does NOT
     * automatically execute helpers - the caller is responsible for processing them.
     *
     * @param actionName - The name of the action to call
     * @param payload - Optional JSON payload to send with the request
     * @returns Promise resolving to the ActionResponse
     */
    callAction(
        actionName: string,
        payload?: Record<string, unknown>
    ): Promise<import('@/core/ActionClient').ActionResponse>;

    // Utility methods
    buildRemoteUrl(base: string, args: Record<string, string | number>): string;

    addFragmentQuery(urlValue: string): string;

    isSameDomain(loc: Location | HTMLAnchorElement): boolean;

    /**
     * Transform an asset source path by prepending the asset serve path.
     * Used by piko:img and piko:svg components with dynamic :src bindings.
     * Paths that are already absolute URLs or start with / are not transformed.
     * The optional moduleName parameter is used to resolve @/ aliases.
     */
    assetSrc(src: string, moduleName?: string): string;

    // UI methods
    toggleLoader(isVisible: boolean): void;

    updateProgressBar(percentValue: number): void;

    displayError(msg: string): void;

    createLoaderIndicator(color: string): void;

    // Module loading
    loadModuleScripts(doc: Document): void;

    observeLazyModules(): void;

    loadModuleDynamically(moduleEl: HTMLElement): void;

    // Patching
    patchPartial(htmlString: string, cssSelector: string): void;

    // Modal
    openModalIfAvailable(options: ModalRequestOptions): Promise<void>;

    // Helper execution
    executeHelper(event: Event, actionString: string, element: HTMLElement): void;

    executeServerHelper(name: string, args: unknown[], triggerElement: HTMLElement, event?: Event): void;

    // Event bus
    eventBus: EventBus;

    // Hooks API for analytics integrations
    hooks: HooksAPI;

    // Register a helper function (for extensions to use)
    registerHelper(name: string, helper: PPHelper): void;

    // Network status
    readonly isOnline: boolean;

    // Module configuration
    getModuleConfig<T = unknown>(moduleName: string): T | null;
}

// eslint-disable-next-line max-lines-per-function
function createPPFramework(): PPFrameworkInstance {
    // Create hook manager first (other services depend on it)
    const hookManager = createHookManager();

    // Create all services
    const eventBus = createEventBus();
    const spriteSheetManager = createSpriteSheetManager();
    const moduleLoader = createModuleLoader();
    const linkHeaderParser = createLinkHeaderParser();
    const modalManager = createModalManager({hookManager});

    // Browser feature services (created lazily in init)
    let networkStatus: NetworkStatus | null = null;
    let a11yAnnouncer: A11yAnnouncer | null = null;
    let formStateManager: FormStateManager | null = null;

    // These are created lazily after init() is called
    let loader: ReturnType<typeof createLoaderUI> | null = null;
    let errorDisplay: ReturnType<typeof createErrorDisplay> | null = null;
    let fetchClient: ReturnType<typeof createFetchClient> | null = null;
    let router: ReturnType<typeof createRouter> | null = null;
    let actionClient: ReturnType<typeof createActionClient> | null = null;
    let remoteRenderer: ReturnType<typeof createRemoteRenderer> | null = null;
    let domBinder: ReturnType<typeof createDOMBinder> | null = null;
    let syncPartialManager: ReturnType<typeof createSyncPartialManager> | null = null;

    // Backwards compatibility state
    let globalConfig: PPFrameworkOptions = {};

    // Module config cache (parsed once from DOM)
    let moduleConfigCache: Record<string, unknown> | null = null;

    // Function to bind DOM after navigation/render
    function bindDOM(root: HTMLElement): void {
        domBinder?.bind(root);
        syncPartialManager?.bind(root);
    }

    /**
     * Scrolls to an anchor element synchronously (no frame delay)
     */
    function scrollToAnchor(hash: string): void {
        if (!hash || hash === '#') {
            return;
        }

        const elementId = hash.slice(1); // Remove leading #
        const element = document.getElementById(elementId);

        if (element) {
            // Use instant scroll to avoid animation during page transition
            element.scrollIntoView({behavior: 'instant', block: 'start'});
        }
    }

    /**
     * Handles scroll position restoration synchronously
     * Must be called in the same execution context as DOM replacement
     */
    function handleScrollPosition(scrollOptions: PageLoadScrollOptions): void {
        if (scrollOptions.restoreScrollY !== undefined) {
            // Restore saved scroll position (back/forward navigation)
            window.scrollTo({top: scrollOptions.restoreScrollY, behavior: 'instant'});
        } else if (scrollOptions.hash) {
            // Scroll to anchor
            scrollToAnchor(scrollOptions.hash);
        } else {
            // New navigation: scroll to top
            window.scrollTo({top: 0, behavior: 'instant'});
        }
    }

    /**
     * Performs the DOM update operations synchronously
     * Extracted to be used with or without View Transitions API
     */
    function performDOMUpdate(
        parsedDocument: Document,
        oldAppRoot: Element,
        newAppRoot: Element,
        scrollOptions: PageLoadScrollOptions
    ): void {
        // Run PK page cleanup before replacing content
        _runPageCleanup();

        // Clear page context (exported functions from previous page script)
        getGlobalPageContext().clear();

        // Replace content
        oldAppRoot.innerHTML = newAppRoot.innerHTML;

        // Handle scroll position SYNCHRONOUSLY - in same execution context as DOM swap
        // This prevents the flicker where content is shown at wrong scroll position
        handleScrollPosition(scrollOptions);

        // Bind DOM handlers
        bindDOM(oldAppRoot as HTMLElement);

        // Load modules from new content
        moduleLoader.loadFromDocument(parsedDocument);

        // Load PK page and partial scripts if present (for p-on:* local function calls)
        // Pass partial name for scoped function registration
        const pageScriptMetas = parsedDocument.querySelectorAll('meta[name="pk-script"]');
        for (const meta of pageScriptMetas) {
            const scriptUrl = meta.getAttribute('content');
            const partialName = meta.getAttribute('data-partial-name');
            if (scriptUrl) {
                // Fire-and-forget async load - handlers will work once module loads
                void getGlobalPageContext().loadModule(scriptUrl, partialName ?? undefined);
            }
        }

        // Register partial instances from DOM for scoped function resolution
        registerPartialInstancesFromDOM(parsedDocument);

        // Execute onConnected lifecycle for partials after navigation
        // If modules haven't loaded yet, _registerLifecycle will fire onConnected when they do
        _executeConnectedForPartials(oldAppRoot);

        // Handle page-specific styles
        // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- head may be null in edge cases
        const newPageStyle = parsedDocument.head?.querySelector('style[pp-page]') ?? parsedDocument.querySelector('style[pp-page]');
        const oldPageStyle = document.head.querySelector('style[pp-page]');

        if (oldPageStyle) {
            oldPageStyle.remove();
        }

        if (newPageStyle) {
            const clonedStyle = newPageStyle.cloneNode(true) as HTMLStyleElement;
            document.head.appendChild(clonedStyle);
        }

        // Update title
        const newTitle = parsedDocument.querySelector('title');
        if (newTitle) {
            // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- textContent may be null
            document.title = (newTitle.textContent ?? '').trim();
        }

        // Observe lazy modules
        moduleLoader.observeLazyModules();
    }

    // Handle page load after navigation
    function handlePageLoad(
        parsedDocument: Document,
        _targetUrl: string,
        scrollOptions: PageLoadScrollOptions
    ): void {
        const newSpriteSheet = parsedDocument.getElementById('sprite') as SVGSVGElement | null;
        spriteSheetManager.merge(newSpriteSheet);

        const newAppRoot = parsedDocument.querySelector('#app');
        const oldAppRoot = document.querySelector('#app');

        if (!oldAppRoot || !newAppRoot) {
            return;
        }

        // Use View Transitions API if available for smoother transitions
        // This wraps the DOM update in a transition that captures before/after states
        if ('startViewTransition' in document && typeof document.startViewTransition === 'function') {
            document.startViewTransition(() => {
                performDOMUpdate(parsedDocument, oldAppRoot, newAppRoot, scrollOptions);
            });
        } else {
            // Fallback: perform update synchronously
            performDOMUpdate(parsedDocument, oldAppRoot, newAppRoot, scrollOptions);
        }
    }

    const instance: PPFrameworkInstance = {
        // Backwards compatibility state accessors
        get loadedModuleScripts() {
            return moduleLoader.getLoadedModules();
        },
        get navigating() {
            return router?.isNavigating() ?? false;
        },
        set navigating(_value: boolean) {
            // No-op for backwards compatibility - navigation state is managed internally
        },
        get loaderElement() {
            return document.getElementById('ppf-loader-bar') as HTMLDivElement | null;
        },
        set loaderElement(_value: HTMLDivElement | null) {
            // No-op for backwards compatibility
        },
        get currentAbortController() {
            return fetchClient?.getController() ?? null;
        },
        set currentAbortController(_value: AbortController | null) {
            // No-op for backwards compatibility
        },
        get globalConfig() {
            return globalConfig;
        },
        set globalConfig(value: PPFrameworkOptions) {
            globalConfig = value;
            router?.setConfig({
                beforeNavigate: value.beforeNavigate,
                afterNavigate: value.afterNavigate
            });
        },

        // Event bus
        eventBus,

        // Hooks API for analytics integrations
        hooks: hookManager.api,

        // Register a helper function (for extensions to use)
        registerHelper: globalHelperRegistry.register.bind(globalHelperRegistry),

        // Network status
        get isOnline() {
            return networkStatus?.isOnline ?? navigator.onLine;
        },

        // Module configuration
        getModuleConfig<T = unknown>(moduleName: string): T | null {
            // Parse config from DOM on first access (lazy initialization)
            if (moduleConfigCache === null) {
                const configEl = document.getElementById('pp-module-config');
                if (configEl?.textContent) {
                    try {
                        moduleConfigCache = JSON.parse(configEl.textContent) as Record<string, unknown>;
                    } catch {
                        console.warn('[PPFramework] Failed to parse module config JSON');
                        moduleConfigCache = {};
                    }
                } else {
                    moduleConfigCache = {};
                }
            }
            return (moduleConfigCache[moduleName] as T) ?? null;
        },

        // Initialisation
        init(options: PPFrameworkOptions = {}) {
            globalConfig = options;

            // Create UI services
            loader = createLoaderUI({color: options.loaderColor ?? '#29e'});
            errorDisplay = createErrorDisplay();

            // Create browser feature services
            networkStatus = createNetworkStatus({hookManager});
            a11yAnnouncer = createA11yAnnouncer();
            formStateManager = createFormStateManager({hookManager});

            // Create fetch client
            fetchClient = createFetchClient();

            // Create action client
            actionClient = createActionClient({
                helperRegistry: globalHelperRegistry,
                errorDisplay,
                hookManager,
                formStateManager
            });

            // Create remote renderer
            remoteRenderer = createRemoteRenderer({
                moduleLoader,
                spriteSheetManager,
                linkHeaderParser,
                onDOMUpdated: bindDOM,
                hookManager
            });

            // Create router
            router = createRouter({
                fetchClient,
                loader,
                errorDisplay,
                eventBus,
                onPageLoad: handlePageLoad,
                hookManager,
                formStateManager,
                a11yAnnouncer
            });

            router.setConfig({
                beforeNavigate: options.beforeNavigate,
                afterNavigate: options.afterNavigate
            });

            // Create DOM binder
            domBinder = createDOMBinder(globalHelperRegistry, {
                onNavigate: (url, _event) => {
                    void instance.navigateTo(url);
                },
                onServerAction: (name, element, event, method, args) => {
                    actionClient?.runAction(name, element, event, method, args);
                },
                onOpenModal: (opts: OpenModalOptions) => {
                    void modalManager.openIfAvailable({
                        selector: opts.selector,
                        params: opts.params,
                        title: opts.title,
                        message: opts.message,
                        cancelLabel: opts.cancelLabel,
                        confirmLabel: opts.confirmLabel,
                        confirmAction: opts.confirmAction,
                        triggerElement: opts.element
                    });
                }
            });

            // Create sync partial manager
            syncPartialManager = createSyncPartialManager({
                onRemoteRender: (renderOptions) => instance.remoteRender(renderOptions)
            });

            // Ensure sprite sheet exists
            spriteSheetManager.ensureExists();

            // Initialise module loader with existing scripts
            initModuleLoaderFromPage(moduleLoader);

            // Observe lazy modules
            moduleLoader.observeLazyModules();

            // Load PK page and partial scripts if present (for p-on:* local function calls)
            // Pass partial name for scoped function registration
            const pageScriptMetas = document.querySelectorAll('meta[name="pk-script"]');
            for (const meta of pageScriptMetas) {
                const scriptUrl = meta.getAttribute('content');
                const partialName = meta.getAttribute('data-partial-name');
                if (scriptUrl) {
                    void getGlobalPageContext().loadModule(scriptUrl, partialName ?? undefined);
                }
            }

            // Register partial instances from DOM for scoped function resolution
            registerPartialInstancesFromDOM(document);

            // Execute onConnected lifecycle for partials on initial page load
            // This runs after module scripts have been loaded and registered their lifecycle callbacks
            _executeConnectedForPartials(document);

            // Bind event handlers to initial page content
            const appRoot = document.querySelector('#app') as HTMLElement | null;
            if (appRoot) {
                bindDOM(appRoot);
            }

            // Scan and track all forms
            formStateManager.scanAndTrackForms();

            // Process any pre-init hook registrations
            hookManager.processQueue();

            // Emit framework ready event
            hookManager.emit(HookEvent.FRAMEWORK_READY, {
                version: '1.0.0',
                loadTime: performance.now(),
                timestamp: Date.now()
            });

            // Emit initial page view
            hookManager.emit(HookEvent.PAGE_VIEW, {
                url: window.location.href,
                title: document.title,
                referrer: document.referrer,
                isInitialLoad: true,
                timestamp: Date.now()
            });
        },

        // Navigation
        async navigateTo(targetUrl: string, evt?: Event, options: NavigateOptions = {}): Promise<void> {
            if (!router) {
                console.warn('PPFramework: navigateTo called before init()');
                return;
            }
            return router.navigateTo(targetUrl, evt, options);
        },

        // Remote rendering
        async remoteRender(options: RemoteRenderOptions): Promise<void> {
            if (!remoteRenderer) {
                console.warn('PPFramework: remoteRender called before init()');
                return;
            }
            return remoteRenderer.render(options);
        },

        // Server actions
        runServerAction(
            actionName: string,
            element: HTMLElement,
            evt?: Event,
            httpMethod: string = 'POST',
            actionArgs: ActionArg[] = []
        ): void {
            if (!actionClient) {
                console.warn('PPFramework: runServerAction called before init()');
                return;
            }
            actionClient.runAction(actionName, element, evt, httpMethod, actionArgs);
        },

        // Programmatic action calls
        async callAction(
            actionName: string,
            payload?: Record<string, unknown>
        ): Promise<import('@/core/ActionClient').ActionResponse> {
            if (!actionClient) {
                throw new Error('PPFramework: callAction called before init()');
            }
            return actionClient.callAction(actionName, payload);
        },

        // Utility methods (delegate to URLUtils)
        buildRemoteUrl,
        addFragmentQuery,
        isSameDomain,

        // Asset path transformation for piko:img/piko:svg dynamic bindings
        assetSrc(src: string, moduleName?: string): string {
            // Skip empty, URLs, data URIs, and absolute paths
            if (!src ||
                src.startsWith('http://') ||
                src.startsWith('https://') ||
                src.startsWith('data:') ||
                src.startsWith('/')) {
                return src;
            }
            // Resolve @/ alias to module path
            let resolvedSrc = src;
            if (src.startsWith('@/') && moduleName) {
                resolvedSrc = moduleName + '/' + src.slice(2);
            }
            return '/_pp/assets/' + resolvedSrc;
        },

        // UI methods
        createLoaderIndicator(color: string) {
            if (loader) {
                loader.destroy();
            }
            loader = createLoaderUI({color});
        },

        toggleLoader(isVisible: boolean) {
            if (!loader) {
                return;
            }
            if (isVisible) {
                loader.show();
            } else {
                loader.hide();
            }
        },

        updateProgressBar(percentValue: number) {
            loader?.setProgress(percentValue);
        },

        displayError(msg: string) {
            errorDisplay?.show(msg);
        },

        // Module loading
        loadModuleScripts(doc: Document) {
            moduleLoader.loadFromDocument(doc);
        },

        observeLazyModules() {
            moduleLoader.observeLazyModules();
        },

        loadModuleDynamically(moduleEl: HTMLElement) {
            moduleLoader.loadDynamically(moduleEl);
        },

        // Patching
        patchPartial(htmlString: string, cssSelector: string) {
            remoteRenderer?.patchPartial(htmlString, cssSelector);
        },

        // Modal
        async openModalIfAvailable(options: ModalRequestOptions): Promise<void> {
            return modalManager.openIfAvailable(options);
        },

        // Helper execution
        executeHelper(event: Event, actionString: string, element: HTMLElement) {
            event.preventDefault();

            const match = actionString.match(/(\w+)(?:\((.*)\))?/);
            if (!match) {
                console.warn(`PPFramework: Could not parse helper action string: "${actionString}"`);
                return;
            }

            const helperName = match[1];
            // eslint-disable-next-line @typescript-eslint/no-unnecessary-condition -- match[2] may be undefined
            const paramsStr = match[2] ?? '';

            const args = paramsStr
                .split(',')
                .map(p => p.trim())
                .filter(p => p);

            globalHelperRegistry.execute(helperName, element, event, args);
        },

        executeServerHelper(name: string, args: unknown[], triggerElement: HTMLElement, event?: Event) {
            actionClient?.executeServerHelper(name, args, triggerElement, event);
        }
    };

    return instance;
}

// ============================================================================
// Global Singleton Instance
// ============================================================================

export const PPFramework = createPPFramework();

// ============================================================================
// Auto-initialise DOM bindings on DOMContentLoaded
// ============================================================================

document.addEventListener('DOMContentLoaded', () => {
    // PPFramework.init() must be called by the application
    // This just ensures DOM is ready for binding if init() was called earlier
});
