/**
 * ActionExecutor - Handles action descriptor lifecycle
 *
 * Executes server actions with:
 * - Optimistic updates before server call
 * - Loading state management
 * - Success/error/complete callbacks
 * - Action chaining via onSuccess return
 * - CSRF token from meta tags
 * - Debounce support
 * - Retry with exponential/linear backoff
 * - Global error handler hook
 */

import type {ActionDescriptor, ActionError, RetryConfig} from '@/pk/action';
import {isActionDescriptor, createActionError} from '@/pk/action';
import {getCSRFTokensFromMeta} from './CSRFUtils';

// ============================================================================
// Types
// ============================================================================

/** Response data from action endpoint */
interface ActionResponseData {
    status?: number;
    message?: string;
    error?: string;
    errors?: Record<string, string[]>;
    data?: unknown;
}

/** Global error handler function type */
export type GlobalActionErrorHandler = (
    error: ActionError,
    descriptor: ActionDescriptor
) => void;

// ============================================================================
// Constants
// ============================================================================

/** HTTP status codes */
const HTTP_STATUS_UNPROCESSABLE = 422;

/** CSS class for loading state */
const LOADING_CLASS = 'pp-loading';

/** ARIA attribute for loading state */
const ARIA_BUSY_ATTR = 'aria-busy';

/** Default retry delays in ms */
const DEFAULT_RETRY_BASE_DELAY = 1000;

/** Maximum retry delay in ms (cap for exponential backoff) */
const MAX_RETRY_DELAY = 30000;

// ============================================================================
// Global State
// ============================================================================

/** Debounce timers keyed by action name + element */
const debounceTimers = new Map<string, ReturnType<typeof setTimeout>>();

/** Global error handler (optional) */
let globalErrorHandler: GlobalActionErrorHandler | null = null;

// ============================================================================
// Global Error Handler
// ============================================================================

/**
 * Registers a global error handler for all action errors
 *
 * This handler is called for every action error, regardless of whether
 * the action has its own onError callback. Useful for analytics, logging,
 * or global error UI.
 *
 * @param handler - The error handler function
 * @returns A function to unregister the handler
 *
 * @example
 * ```typescript
 * const unsubscribe = onActionError((error, descriptor) => {
 *     analytics.track('action_error', {
 *         action: descriptor.action,
 *         status: error.status
 *     });
 *
 *     if (error.isAuthError) {
 *         navigate('/login');
 *     }
 * });
 * ```
 */
export function onActionError(handler: GlobalActionErrorHandler): () => void {
    globalErrorHandler = handler;
    return () => {
        if (globalErrorHandler === handler) {
            globalErrorHandler = null;
        }
    };
}

/**
 * Clears the global error handler (mainly for testing)
 */
export function clearGlobalErrorHandler(): void {
    globalErrorHandler = null;
}

// ============================================================================
// Loading State Management
// ============================================================================

/**
 * Shows loading state on target element(s)
 */
function showLoading(target: string | HTMLElement | boolean, element: HTMLElement): void {
    if (target === true) {
        element.classList.add(LOADING_CLASS);
        element.setAttribute(ARIA_BUSY_ATTR, 'true');
    } else if (typeof target === 'string') {
        const el = document.querySelector<HTMLElement>(target);
        if (el) {
            el.classList.add(LOADING_CLASS);
            el.setAttribute(ARIA_BUSY_ATTR, 'true');
        }
    } else if (target instanceof HTMLElement) {
        target.classList.add(LOADING_CLASS);
        target.setAttribute(ARIA_BUSY_ATTR, 'true');
    }
}

/**
 * Hides loading state from target element(s)
 */
function hideLoading(target: string | HTMLElement | boolean, element: HTMLElement): void {
    if (target === true) {
        element.classList.remove(LOADING_CLASS);
        element.removeAttribute(ARIA_BUSY_ATTR);
    } else if (typeof target === 'string') {
        const el = document.querySelector<HTMLElement>(target);
        if (el) {
            el.classList.remove(LOADING_CLASS);
            el.removeAttribute(ARIA_BUSY_ATTR);
        }
    } else if (target instanceof HTMLElement) {
        target.classList.remove(LOADING_CLASS);
        target.removeAttribute(ARIA_BUSY_ATTR);
    }
}

// ============================================================================
// Retry Logic
// ============================================================================

/**
 * Calculates the delay for a retry attempt
 *
 * @param attempt - Current attempt number (0-based)
 * @param config - Retry configuration
 * @returns Delay in milliseconds
 */
function calculateRetryDelay(attempt: number, config: RetryConfig): number {
    const backoff = config.backoff ?? 'exponential';

    if (backoff === 'linear') {
        // Linear: 1s, 2s, 3s, 4s...
        return Math.min(DEFAULT_RETRY_BASE_DELAY * (attempt + 1), MAX_RETRY_DELAY);
    }

    // Exponential: 1s, 2s, 4s, 8s...
    return Math.min(DEFAULT_RETRY_BASE_DELAY * Math.pow(2, attempt), MAX_RETRY_DELAY);
}

/**
 * Waits for the specified delay
 */
function delay(ms: number): Promise<void> {
    return new Promise(resolve => setTimeout(resolve, ms));
}

/**
 * Executes the server action with retry support
 */
async function executeWithRetry(
    actionName: string,
    args: unknown[],
    method: string,
    actionToken: string | null,
    ephemeralToken: string | null,
    retryConfig?: RetryConfig
): Promise<unknown> {
    const maxAttempts = retryConfig?.attempts ?? 1;
    let lastError: ActionError | null = null;

    for (let attempt = 0; attempt < maxAttempts; attempt++) {
        try {
            return await executeServerAction(actionName, args, method, actionToken, ephemeralToken);
        } catch (error) {
            // Handle both ActionError (from server) and plain Error (network failure)
            if (error instanceof Error && !('status' in error)) {
                // Network error - convert to ActionError with status 0
                lastError = createActionError(0, error.message);
            } else {
                lastError = error as ActionError;
            }

            // Don't retry client errors (4xx) except network errors (status 0)
            const isRetryable = lastError.status === 0 || lastError.status >= 500;

            if (!isRetryable || attempt >= maxAttempts - 1) {
                throw lastError;
            }

            // Wait before retrying
            const retryDelay = calculateRetryDelay(attempt, retryConfig!);
            await delay(retryDelay);
        }
    }

    // Should not reach here, but throw last error just in case
    throw lastError;
}

// ============================================================================
// Server Communication
// ============================================================================

/**
 * Executes the server action via fetch
 */
async function executeServerAction(
    actionName: string,
    args: unknown[],
    method: string,
    actionToken: string | null,
    ephemeralToken: string | null
): Promise<unknown> {
    const headers: HeadersInit = {
        'Content-Type': 'application/json'
    };

    // Add CSRF action token header
    if (actionToken) {
        headers['X-CSRF-Action-Token'] = actionToken;
    }

    // Build body with args and ephemeral token
    const bodyData: Record<string, unknown> = {};

    if (args.length > 0) {
        // Format args as indexed object to match ActionClient format
        bodyData['args'] = args
            .map((v, i) => ({[i]: v}))
            .reduce((acc, b) => ({...acc, ...b}), {});
    }

    if (ephemeralToken) {
        bodyData['_csrf_ephemeral_token'] = ephemeralToken;
    }

    const response = await fetch(`/_pp/actions/${actionName}?_f=1`, {
        method,
        headers,
        credentials: 'same-origin',
        body: JSON.stringify(bodyData)
    });

    // Parse response
    let responseData: ActionResponseData;
    try {
        responseData = (await response.json()) as ActionResponseData;
    } catch {
        throw createActionError(
            response.status,
            'Failed to parse server response',
            undefined,
            undefined
        );
    }

    if (!response.ok) {
        // Build validation errors if present
        const validationErrors = response.status === HTTP_STATUS_UNPROCESSABLE
            ? responseData.errors
            : undefined;

        throw createActionError(
            response.status,
            responseData.message ?? responseData.error ?? `Action failed with status ${response.status}`,
            validationErrors,
            responseData.data
        );
    }

    // Return the response data for success callback
    return responseData.data ?? responseData;
}

// ============================================================================
// Debounce Support
// ============================================================================

/**
 * Generates a unique key for debouncing based on action and element
 */
function getDebounceKey(actionName: string, element: HTMLElement): string {
    // Use element's unique identifier or create one
    if (!element.dataset.ppActionId) {
        element.dataset.ppActionId = `action-${Date.now()}-${Math.random().toString(36).slice(2, 9)}`;
    }
    return `${actionName}:${element.dataset.ppActionId}`;
}

/**
 * Clears any pending debounced action for the given key
 */
function clearDebounce(key: string): void {
    const timer = debounceTimers.get(key);
    if (timer) {
        clearTimeout(timer);
        debounceTimers.delete(key);
    }
}

/**
 * Clears all debounce timers (mainly for testing)
 */
export function clearAllDebounceTimers(): void {
    for (const timer of debounceTimers.values()) {
        clearTimeout(timer);
    }
    debounceTimers.clear();
}

// ============================================================================
// Main Handler
// ============================================================================

/**
 * Core action execution logic (without debounce wrapper)
 */
async function executeAction(
    descriptor: ActionDescriptor,
    element: HTMLElement,
    event?: Event
): Promise<void> {
    // 1. Run optimistic update immediately (synchronous)
    if (descriptor.optimistic) {
        try {
            descriptor.optimistic();
        } catch (error) {
            console.error('[ActionExecutor] Optimistic update failed:', error);
        }
    }

    // 2. Show loading state
    if (descriptor.loading !== undefined) {
        showLoading(descriptor.loading, element);
    }

    try {
        // 3. Get CSRF tokens from meta tags
        const {actionToken, ephemeralToken} = getCSRFTokensFromMeta();

        // 4. Call server action (with retry if configured)
        const response = await executeWithRetry(
            descriptor.action,
            descriptor.args ?? [],
            descriptor.method ?? 'POST',
            actionToken,
            ephemeralToken,
            descriptor.retry
        );

        // 5. Success callback
        if (descriptor.onSuccess) {
            try {
                const next = descriptor.onSuccess(response);

                // Chain another action if returned
                if (isActionDescriptor(next)) {
                    await handleAction(next, element, event);
                }
            } catch (error) {
                console.error('[ActionExecutor] onSuccess callback failed:', error);
            }
        }
    } catch (error) {
        const actionError = error as ActionError;

        // 6. Call global error handler first (if registered)
        if (globalErrorHandler) {
            try {
                globalErrorHandler(actionError, descriptor);
            } catch (handlerError) {
                console.error('[ActionExecutor] Global error handler failed:', handlerError);
            }
        }

        // 7. Error callback (for rollback)
        if (descriptor.onError) {
            try {
                descriptor.onError(actionError);
            } catch (callbackError) {
                console.error('[ActionExecutor] onError callback failed:', callbackError);
            }
        } else if (!globalErrorHandler) {
            // Default error handling if no onError provided and no global handler
            console.error('[ActionExecutor] Action failed:', error);
        }
    } finally {
        // 8. Complete callback (always runs)
        if (descriptor.onComplete) {
            try {
                descriptor.onComplete();
            } catch (error) {
                console.error('[ActionExecutor] onComplete callback failed:', error);
            }
        }

        // 9. Hide loading state
        if (descriptor.loading !== undefined) {
            hideLoading(descriptor.loading, element);
        }
    }
}

/**
 * Handles an action descriptor through its full lifecycle
 *
 * 1. Applies debounce if configured
 * 2. Runs optimistic update immediately
 * 3. Shows loading state
 * 4. Calls server action (with retry if configured)
 * 5. On success: calls onSuccess, chains if it returns another action
 * 6. On error: calls global handler, then onError for rollback
 * 7. Always: calls onComplete, hides loading
 *
 * @param descriptor - The action descriptor to execute
 * @param element - The triggering element (for loading state)
 * @param event - The original event (optional)
 */
export async function handleAction(
    descriptor: ActionDescriptor,
    element: HTMLElement,
    event?: Event
): Promise<void> {
    // Handle debounce if configured
    if (descriptor.debounce && descriptor.debounce > 0) {
        const debounceKey = getDebounceKey(descriptor.action, element);

        // Clear any pending debounced action
        clearDebounce(debounceKey);

        // Schedule the action
        return new Promise<void>((resolve) => {
            const timer = setTimeout(() => {
                debounceTimers.delete(debounceKey);
                executeAction(descriptor, element, event).then(resolve);
            }, descriptor.debounce);

            debounceTimers.set(debounceKey, timer);
        });
    }

    // Execute immediately if no debounce
    return executeAction(descriptor, element, event);
}
